Here's a Rust CLI application that monitors and synchronizes directories as requested:

```rust
use clap::{App, Arg};
use log::{error, info, LevelFilter};
use notify::{Config, Event, RecommendedWatcher, RecursiveMode, Watcher};
use std::collections::HashMap;
use std::fs::{self, File, Permissions};
use std::os::unix::fs::PermissionsExt;
use std::path::{Path, PathBuf};
use std::sync::mpsc::channel;
use std::time::{Duration, SystemTime};
use std::{io, process};
use tokio::fs as tokio_fs;
use tokio::io::AsyncWriteExt;

#[derive(Debug)]
struct BackupItem {
    timestamp: SystemTime,
    path: PathBuf,
}

struct BackupHistory {
    history: HashMap<PathBuf, Vec<BackupItem>>,
    max_history_per_file: usize,
}

impl BackupHistory {
    fn new(max_history_per_file: usize) -> Self {
        BackupHistory {
            history: HashMap::new(),
            max_history_per_file,
        }
    }

    fn add_backup(&mut self, source_path: &Path, backup_path: PathBuf) {
        let entry = self.history.entry(source_path.to_path_buf()).or_insert_with(Vec::new);
        entry.push(BackupItem {
            timestamp: SystemTime::now(),
            path: backup_path,
        });

        // Limit history size
        if entry.len() > self.max_history_per_file {
            entry.sort_by(|a, b| a.timestamp.cmp(&b.timestamp));
            while entry.len() > self.max_history_per_file {
                if let Some(oldest) = entry.first() {
                    let path = oldest.path.clone();
                    let _ = fs::remove_file(&path);
                    info!("Removed old backup: {:?}", path);
                }
                entry.remove(0);
            }
        }
    }

    fn get_backups(&self, path: &Path) -> Vec<BackupItem> {
        self.history
            .get(path)
            .cloned()
            .unwrap_or_else(Vec::new)
    }
}

async fn create_backup(
    source_path: &Path,
    backup_dir: &Path,
    history: &mut BackupHistory,
) -> io::Result<()> {
    if !source_path.exists() {
        return Err(io::Error::new(
            io::ErrorKind::NotFound,
            "Source path does not exist",
        ));
    }

    // Create relative path from source
    let source_name = source_path.file_name().unwrap_or_default();
    let timestamp = chrono::Local::now().format("%Y%m%d%H%M%S");
    let backup_filename = format!("{}_{}", source_name.to_string_lossy(), timestamp);
    let backup_path = backup_dir.join(backup_filename);

    // Get original permissions
    let metadata = fs::metadata(source_path)?;
    let permissions = metadata.permissions();

    // Copy file with original permissions
    let content = tokio_fs::read(source_path).await?;
    let mut file = tokio_fs::File::create(&backup_path).await?;
    file.write_all(&content).await?;
    file.flush().await?;

    // Set same permissions as original
    fs::set_permissions(&backup_path, permissions)?;

    // Add to history
    history.add_backup(source_path, backup_path);

    info!("Created backup of {:?}", source_path);
    Ok(())
}

async fn sync_files(
    source_path: &Path,
    dest_path: &Path,
    history: &mut BackupHistory,
    backup_dir: &Path,
) -> io::Result<()> {
    if source_path.is_file() {
        // Create backup before overwriting
        create_backup(dest_path, backup_dir, history).await.ok();

        // Get original permissions
        let metadata = fs::metadata(source_path)?;
        let permissions = metadata.permissions();

        // Copy with permissions preserved
        let content = tokio_fs::read(source_path).await?;
        let parent = dest_path.parent().unwrap_or_else(|| Path::new(""));
        tokio_fs::create_dir_all(parent).await?;

        let mut file = tokio_fs::File::create(dest_path).await?;
        file.write_all(&content).await?;
        file.flush().await?;

        // Set same permissions as original
        fs::set_permissions(dest_path, permissions)?;

        info!("Synced file {:?} to {:?}", source_path, dest_path);
    } else if source_path.is_dir() {
        tokio_fs::create_dir_all(dest_path).await?;

        // Set same permissions as original
        let metadata = fs::metadata(source_path)?;
        let permissions = metadata.permissions();
        fs::set_permissions(dest_path, permissions)?;

        info!("Created directory {:?}", dest_path);
    }

    Ok(())
}

async fn handle_event(
    event: Event,
    source_dir: &Path,
    backup_dir: &Path,
    destination_dir: &Path,
    history: &mut BackupHistory,
) -> io::Result<()> {
    for path in event.paths {
        if !path.starts_with(source_dir) {
            continue;
        }

        let relative_path = path.strip_prefix(source_dir).unwrap_or(&path);
        let destination = destination_dir.join(relative_path);

        match event.kind {
            notify::EventKind::Create(_) | notify::EventKind::Modify(_) => {
                sync_files(&path, &destination, history, backup_dir).await?;
            }
            notify::EventKind::Remove(_) => {
                if destination.exists() {
                    // Create backup before removing
                    create_backup(&destination, backup_dir, history).await.ok();

                    if destination.is_file() {
                        tokio_fs::remove_file(&destination).await?;
                    } else if destination.is_dir() {
                        tokio_fs::remove_dir_all(&destination).await?;
                    }

                    info!("Removed {:?} from destination", destination);
                }
            }
            _ => {}
        }
    }

    Ok(())
}

fn init_logger() -> Result<(), fern::InitError> {
    fern::Dispatch::new()
        .format(|out, message, record| {
            out.finish(format_args!(
                "{}[{}][{}] {}",
                chrono::Local::now().format("[%Y-%m-%d][%H:%M:%S]"),
                record.target(),
                record.level(),
                message
            ))
        })
        .level(LevelFilter::Info)
        .chain(std::io::stdout())
        .chain(fern::log_file("sync_backup.log")?)
        .apply()?;
    Ok(())
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Initialize logger
    if let Err(e) = init_logger() {
        eprintln!("Failed to initialize logger: {}", e);
    }

    // Parse command line arguments
    let matches = App::new("Directory Synchronizer")
        .version("1.0.0")
        .author("Directory Sync Team")
        .about("Synchronizes directories in real-time")
        .arg(
            Arg::with_name("source")
                .short("s")
                .long("source")
                .value_name("SOURCE_DIR")
                .help("Sets the source directory to watch")
                .required(true)
                .takes_value(true),
        )
        .arg(
            Arg::with_name("destination")
                .short("d")
                .long("destination")
                .value_name("DESTINATION_DIR")
                .help("Sets the destination directory for synchronization")
                .required(true)
                .takes_value(true),
        )
        .arg(
            Arg::with_name("backup")
                .short("b")
                .long("backup")
                .value_name("BACKUP_DIR")
                .help("Sets the backup directory for history")
                .required(true)
                .takes_value(true),
        )
        .get_matches();

    let source_dir = PathBuf::from(matches.value_of("source").unwrap());
    let destination_dir = PathBuf::from(matches.value_of("destination").unwrap());
    let backup_dir = PathBuf::from(matches.value_of("backup").unwrap());

    // Validate directories
    if !source_dir.exists() || !source_dir.is_dir() {
        error!("Source directory does not exist or is not a directory");
        process::exit(1);
    }

    // Create destination and backup directories if they don't exist
    fs::create_dir_all(&destination_dir)?;
    fs::create_dir_all(&backup_dir)?;

    // Initialize history tracker
    let mut history = BackupHistory::new(10); // Keep 10 backups per file

    // Initial synchronization
    info!("Performing initial synchronization...");
    for entry in walkdir::WalkDir::new(&source_dir) {
        let entry = entry?;
        let path = entry.path();
        let relative_path = path.strip_prefix(&source_dir)?;
        let dest_path = destination_dir.join(relative_path);

        if path.is_file() {
            sync_files(path, &dest_path, &mut history, &backup_dir).await?;
        } else if path.is_dir() && !dest_path.exists() {
            fs::create_dir_all(&dest_path)?;

            // Copy permissions
            let metadata = fs::metadata(path)?;
            let permissions = metadata.permissions();
            fs::set_permissions(&dest_path, permissions)?;
        }
    }
    info!("Initial synchronization complete");

    // Set up file watcher
    let (tx, rx) = channel();
    let mut watcher = RecommendedWatcher::new(tx, Config::default())?;
    watcher.watch(&source_dir, RecursiveMode::Recursive)?;

    info!("Watching for changes in {:?}", source_dir);

    // Process events
    for res in rx {
        match res {
            Ok(event) => {
                if let Err(e) = handle_event(
                    event,
                    &source_dir,
                    &backup_dir,
                    &destination_dir,
                    &mut history,
                )
                .await
                {
                    error!("Error handling event: {}", e);
                }
            }
            Err(e) => error!("Watch error: {}", e),
        }
    }

    Ok(())
}
