Here's a Rust-based command-line tool that monitors directory changes and organizes files by extension:

```rust
use std::collections::HashMap;
use std::fs::{self, DirEntry};
use std::path::{Path, PathBuf};
use std::sync::mpsc::{channel, Receiver, Sender};
use std::thread;
use std::time::{Duration, SystemTime};

fn main() -> std::io::Result<()> {
    let args: Vec<String> = std::env::args().collect();
    if args.len() != 2 {
        eprintln!("Usage: {} <directory_to_watch>", args[0]);
        std::process::exit(1);
    }

    let watch_dir = &args[1];
    println!("Monitoring directory: {}", watch_dir);

    // Create channel for communication between threads
    let (tx, rx): (Sender<PathBuf>, Receiver<PathBuf>) = channel();

    // Spawn a thread to process file moves
    let processor_thread = thread::spawn(move || {
        let mut processed_files: HashMap<PathBuf, SystemTime> = HashMap::new();
        process_files(rx, &mut processed_files);
    });

    // Main thread watches for file changes
    watch_directory(watch_dir, tx)?;

    processor_thread.join().unwrap();
    Ok(())
}

fn watch_directory(dir: &str, tx: Sender<PathBuf>) -> std::io::Result<()> {
    // Initial scan of directory
    for entry in fs::read_dir(dir)? {
        if let Ok(entry) = entry {
            let path = entry.path();
            if path.is_file() {
                let _ = tx.send(path);
            }
        }
    }

    // Watch for changes
    let path = Path::new(dir);
    let mut last_check = SystemTime::now();

    loop {
        thread::sleep(Duration::from_millis(500));

        // Check for new files periodically
        // This is a simplification - a production version would use proper fs::watch
        // but that requires more complex event handling
        for entry in fs::read_dir(path)? {
            if let Ok(entry) = entry {
                let file_path = entry.path();
                if file_path.is_file() {
                    if let Ok(metadata) = fs::metadata(&file_path) {
                        if let Ok(modified) = metadata.modified() {
                            if modified > last_check {
                                let _ = tx.send(file_path);
                            }
                        }
                    }
                }
            }
        }

        last_check = SystemTime::now();
    }
}

fn process_files(rx: Receiver<PathBuf>, processed_files: &mut HashMap<PathBuf, SystemTime>) {
    let mut workers = Vec::new();

    for _ in 0..4 {  // Create 4 worker threads
        let thread_rx = rx.clone();
        let worker = thread::spawn(move || {
            while let Ok(file_path) = thread_rx.recv() {
                organize_file(&file_path);
            }
        });

        workers.push(worker);
    }

    for worker in workers {
        let _ = worker.join();
    }
}

fn organize_file(file_path: &Path) {
    if let Some(extension) = file_path.extension() {
        let ext_str = extension.to_string_lossy().to_lowercase();

        if let Some(parent_dir) = file_path.parent() {
            let target_dir = parent_dir.join(&ext_str);

            // Create extension directory if it doesn't exist
            if !target_dir.exists() {
                if let Err(e) = fs::create_dir_all(&target_dir) {
                    eprintln!("Failed to create directory for extension {}: {}", ext_str, e);
                    return;
                }
            }

            if let Some(file_name) = file_path.file_name() {
                let target_path = target_dir.join(file_name);

                // Move the file
                match fs::rename(file_path, &target_path) {
                    Ok(_) => println!("Moved {:?} to {:?}", file_path, target_path),
                    Err(e) => eprintln!("Failed to move {:?}: {}", file_path, e),
                }
            }
        }
    }
}
