Now, let's create the main application:

```rust:src/main.rs
use anyhow::{Context, Result};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::fs;
use std::sync::{Arc, Mutex};
use tokio::io::{self, AsyncBufReadExt, BufReader};
use tokio::sync::mpsc;

#[derive(Debug, Clone, Serialize, Deserialize)]
struct InventoryItem {
    name: String,
    quantity: u32,
    store_id: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct Inventory {
    items: Vec<InventoryItem>,
}

type SharedInventory = Arc<Mutex<Inventory>>;

async fn save_inventory(inventory: &SharedInventory, file_path: &str) -> Result<()> {
    let inventory = inventory.lock().unwrap();
    let json = serde_json::to_string_pretty(&*inventory)?;
    fs::write(file_path, json).context("Failed to write inventory to file")?;
    Ok(())
}

async fn load_inventory(file_path: &str) -> Result<Inventory> {
    let data = fs::read_to_string(file_path).context("Failed to read inventory file")?;
    let inventory: Inventory = serde_json::from_str(&data).context("Failed to parse JSON")?;
    Ok(inventory)
}

async fn update_item_quantity(
    inventory: SharedInventory,
    store_id: String,
    item_name: String,
    new_quantity: u32,
    file_path: String,
) -> Result<()> {
    {
        let mut inventory = inventory.lock().unwrap();
        for item in &mut inventory.items {
            if item.store_id == store_id && item.name == item_name {
                item.quantity = new_quantity;
                println!("Updated {} in store {} to quantity {}", item_name, store_id, new_quantity);
                break;
            }
        }
    }

    save_inventory(&inventory, &file_path).await?;
    Ok(())
}

async fn list_stores(inventory: &SharedInventory) -> Vec<String> {
    let inventory = inventory.lock().unwrap();
    let mut stores = HashMap::new();

    for item in &inventory.items {
        stores.insert(item.store_id.clone(), true);
    }

    stores.keys().cloned().collect()
}

async fn list_items_by_store(inventory: &SharedInventory, store_id: &str) -> Vec<InventoryItem> {
    let inventory = inventory.lock().unwrap();
    inventory
        .items
        .iter()
        .filter(|item| item.store_id == store_id)
        .cloned()
        .collect()
}

async fn process_user_input(
    inventory: SharedInventory,
    file_path: String,
    mut rx: mpsc::Receiver<String>,
) {
    while let Some(input) = rx.recv().await {
        let parts: Vec<&str> = input.trim().split_whitespace().collect();

        match parts.get(0).map(|s| *s) {
            Some("update") => {
                if parts.len() != 4 {
                    println!("Usage: update <store_id> <item_name> <new_quantity>");
                    continue;
                }

                let store_id = parts[1].to_string();
                let item_name = parts[2].to_string();
                let new_quantity = match parts[3].parse::<u32>() {
                    Ok(qty) => qty,
                    Err(_) => {
                        println!("Quantity must be a positive number");
                        continue;
                    }
                };

                if let Err(e) = update_item_quantity(
                    inventory.clone(),
                    store_id,
                    item_name,
                    new_quantity,
                    file_path.clone(),
                )
                .await
                {
                    println!("Error updating inventory: {}", e);
                }
            }
            Some("list") => {
                if parts.len() == 1 {
                    // List all stores
                    let stores = list_stores(&inventory).await;
                    println!("Available stores:");
                    for store in stores {
                        println!("- {}", store);
                    }
                } else if parts.len() == 2 {
                    // List items in a specific store
                    let store_id = parts[1];
                    let items = list_items_by_store(&inventory, store_id).await;
                    if items.is_empty() {
                        println!("No items found for store: {}", store_id);
                    } else {
                        println!("Items in store {}:", store_id);
                        for item in items {
                            println!("- {}: {} units", item.name, item.quantity);
                        }
                    }
                } else {
                    println!("Usage: list [store_id]");
                }
            }
            Some("help") => {
                println!("Commands:");
                println!("  update <store_id> <item_name> <new_quantity> - Update item quantity");
                println!("  list - List all stores");
                println!("  list <store_id> - List items in a store");
                println!("  help - Show this help message");
                println!("  exit - Exit the application");
            }
            Some("exit") => {
                println!("Exiting...");
                break;
            }
            _ => {
                println!("Unknown command. Type 'help' for available commands.");
            }
        }
    }
}

#[tokio::main]
async fn main() -> Result<()> {
    // Default inventory file path
    let file_path = "inventory.json";

    // Check if the inventory file exists, create a sample one if not
    if !std::path::Path::new(file_path).exists() {
        let sample_inventory = Inventory {
            items: vec![
                InventoryItem {
                    name: "Laptop".to_string(),
                    quantity: 10,
                    store_id: "store1".to_string(),
                },
                InventoryItem {
                    name: "Phone".to_string(),
                    quantity: 20,
                    store_id: "store1".to_string(),
                },
                InventoryItem {
                    name: "Tablet".to_string(),
                    quantity: 15,
                    store_id: "store2".to_string(),
                },
            ],
        };

        let json = serde_json::to_string_pretty(&sample_inventory)?;
        fs::write(file_path, json)?;
        println!("Created sample inventory file: {}", file_path);
    }

    // Load inventory from file
    let inventory = load_inventory(file_path).await?;
    let shared_inventory = Arc::new(Mutex::new(inventory));

    // Set up channel for user input
    let (tx, rx) = mpsc::channel::<String>(100);

    // Spawn task to process user input
    let process_handle = tokio::spawn(process_user_input(
        shared_inventory.clone(),
        file_path.to_string(),
        rx,
    ));

    println!("Stock Inventory Manager");
    println!("Type 'help' for available commands");

    // Read user input
    let mut stdin = BufReader::new(io::stdin()).lines();
    while let Some(line) = stdin.next_line().await? {
        if line.trim() == "exit" {
            tx.send(line).await?;
            break;
        }

        tx.send(line).await?;
    }

    // Wait for processing to complete
    process_handle.await?;

    Ok(())
}
```

This application:
1. Uses tokio for asynchronous operations
2. Stores inventory data in a JSON file
3. Protects shared data with Mutex from std::sync
4. Handles parallel updates via user inputs
5. Saves changes back to the JSON file in real-time
6. Provides commands for listing and updating inventory

Here's a Rust application for processing and analyzing server logs in near-real-time:

```rust
use std::collections::HashMap;
use std::fs::{self, File};
use std::io::{self, BufRead, BufReader, Error, ErrorKind, SeekFrom};
use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::{Duration, Instant};

use serde::{Deserialize, Serialize};
use serde_json::Value;
use tokio::io::AsyncSeekExt;
use tokio::sync::mpsc;
use tokio::time;

#[derive(Debug, Deserialize, Serialize)]
struct LogEntry {
    timestamp: String,
    level: String,
    message: String,
    service: String,
    response_time_ms: Option<u64>,
    error_code: Option<u32>,
    #[serde(flatten)]
    additional_fields: HashMap<String, Value>,
}

#[derive(Debug, Default)]
struct ServerMetrics {
    total_requests: u64,
    error_count: u64,
    total_response_time: u64,
    max_response_time: u64,
}

struct LogProcessor {
    log_dir: PathBuf,
    file_positions: Arc<Mutex<HashMap<PathBuf, u64>>>,
    metrics: Arc<Mutex<HashMap<String, ServerMetrics>>>,
}

impl LogProcessor {
    fn new<P: AsRef<Path>>(log_dir: P) -> Self {
        LogProcessor {
            log_dir: log_dir.as_ref().to_path_buf(),
            file_positions: Arc::new(Mutex::new(HashMap::new())),
            metrics: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    async fn start_processing(&self) -> io::Result<()> {
        // Create channel for log file discovery
        let (tx, mut rx) = mpsc::channel::<PathBuf>(100);

        // Clone Arc references for the file discovery task
        let log_dir = self.log_dir.clone();
        let file_positions = Arc::clone(&self.file_positions);

        // Spawn file discovery task
        tokio::spawn(async move {
            let mut interval = time::interval(Duration::from_secs(1));
            loop {
                interval.tick().await;
                if let Err(e) = discover_log_files(&log_dir, &tx, &file_positions).await {
                    eprintln!("Error discovering log files: {}", e);
                }
            }
        });

        // Process discovered log files
        while let Some(log_file) = rx.recv().await {
            let file_positions = Arc::clone(&self.file_positions);
            let metrics = Arc::clone(&self.metrics);

            tokio::spawn(async move {
                if let Err(e) = process_log_file(&log_file, &file_positions, &metrics).await {
                    eprintln!("Error processing log file {}: {}", log_file.display(), e);
                }
            });
        }

        Ok(())
    }

    fn print_metrics(&self) {
        let metrics = self.metrics.lock().unwrap();
        println!("\n--- Server Metrics Summary ---");

        for (server, metrics) in metrics.iter() {
            let avg_response_time = if metrics.total_requests > 0 {
                metrics.total_response_time as f64 / metrics.total_requests as f64
            } else {
                0.0
            };

            let error_rate = if metrics.total_requests > 0 {
                (metrics.error_count as f64 / metrics.total_requests as f64) * 100.0
            } else {
                0.0
            };

            println!("Server: {}", server);
            println!("  Total Requests: {}", metrics.total_requests);
            println!("  Error Rate: {:.2}%", error_rate);
            println!("  Avg Response Time: {:.2}ms", avg_response_time);
            println!("  Max Response Time: {}ms", metrics.max_response_time);
        }
    }
}

async fn discover_log_files(
    log_dir: &Path,
    tx: &mpsc::Sender<PathBuf>,
    file_positions: &Arc<Mutex<HashMap<PathBuf, u64>>>,
) -> io::Result<()> {
    let entries = fs::read_dir(log_dir)?;

    for entry in entries {
        let entry = entry?;
        let path = entry.path();

        if path.is_file() && path.extension().map_or(false, |ext| ext == "log") {
            // Check if this is a new file
            let mut positions = file_positions.lock().unwrap();
            if !positions.contains_key(&path) {
                positions.insert(path.clone(), 0);
                if let Err(e) = tx.try_send(path) {
                    eprintln!("Failed to send log file path: {}", e);
                }
            }
        }
    }

    Ok(())
}

async fn process_log_file(
    log_file: &Path,
    file_positions: &Arc<Mutex<HashMap<PathBuf, u64>>>,
    metrics: &Arc<Mutex<HashMap<String, ServerMetrics>>>,
) -> io::Result<()> {
    let file = match File::open(log_file) {
        Ok(file) => file,
        Err(e) => {
            return Err(Error::new(
                ErrorKind::Other,
                format!("Failed to open log file: {}", e),
            ));
        }
    };

    let mut reader = BufReader::new(file);

    // Get the last position we read from
    let position = {
        let positions = file_positions.lock().unwrap();
        *positions.get(log_file).unwrap_or(&0)
    };

    // Seek to the last position
    reader.seek(SeekFrom::Start(position))?;

    let mut new_position = position;
    let mut line = String::new();

    loop {
        line.clear();
        let bytes_read = reader.read_line(&mut line)?;

        if bytes_read == 0 {
            // End of file for now, update position and return
            let mut positions = file_positions.lock().unwrap();
            positions.insert(log_file.to_path_buf(), new_position);
            break;
        }

        new_position += bytes_read as u64;

        // Process the log entry
        if let Ok(log_entry) = serde_json::from_str::<LogEntry>(&line) {
            update_metrics(&log_entry, metrics);
        }
    }

    Ok(())
}

fn update_metrics(log_entry: &LogEntry, metrics: &Arc<Mutex<HashMap<String, ServerMetrics>>>) {
    let mut metrics_map = metrics.lock().unwrap();
    let server_metrics = metrics_map
        .entry(log_entry.service.clone())
        .or_insert_with(ServerMetrics::default);

    server_metrics.total_requests += 1;

    if log_entry.error_code.is_some() {
        server_metrics.error_count += 1;
    }

    if let Some(response_time) = log_entry.response_time_ms {
        server_metrics.total_response_time += response_time;
        if response_time > server_metrics.max_response_time {
            server_metrics.max_response_time = response_time;
        }
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let log_dir = std::env::args()
        .nth(1)
        .unwrap_or_else(|| "./logs".to_string());

    println!("Starting server log analyzer");
    println!("Monitoring log directory: {}", log_dir);

    let processor = LogProcessor::new(log_dir);

    // Start a thread to periodically print metrics
    let metrics = Arc::clone(&processor.metrics);
    thread::spawn(move || {
        loop {
            thread::sleep(Duration::from_secs(5));

            let metrics_map = metrics.lock().unwrap();
            println!("\n--- Server Metrics Summary ---");

            for (server, metrics) in metrics_map.iter() {
                let avg_response_time = if metrics.total_requests > 0 {
                    metrics.total_response_time as f64 / metrics.total_requests as f64
                } else {
                    0.0
                };

                let error_rate = if metrics.total_requests > 0 {
                    (metrics.error_count as f64 / metrics.total_requests as f64) * 100.0
                } else {
                    0.0
                };

                println!("Server: {}", server);
                println!("  Total Requests: {}", metrics.total_requests);
                println!("  Error Rate: {:.2}%", error_rate);
                println!("  Avg Response Time: {:.2}ms", avg_response_time);
                println!("  Max Response Time: {}ms", metrics.max_response_time);
            }
        }
    });

    // Start processing logs
    processor.start_processing().await?;

    Ok(())
}
