package com.sentiment;

import com.sun.net.httpserver.HttpExchange;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpServer;

import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;
import java.net.InetSocketAddress;
import java.nio.charset.StandardCharsets;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.Executors;

public class SentimentAnalysisService {
    public static void main(String[] args) throws IOException {
        int port = 8080;
        HttpServer server = HttpServer.create(new InetSocketAddress(port), 0);

        server.createContext("/analyze", new SentimentAnalysisHandler());
        server.setExecutor(Executors.newVirtualThreadPerTaskExecutor());
        server.start();

        System.out.println("Sentiment Analysis Service started on port " + port);
    }

    static class SentimentAnalysisHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if (!"POST".equals(exchange.getRequestMethod())) {
                sendResponse(exchange, 405, "{\"error\": \"Method not allowed\"}");
                return;
            }

            try {
                String requestBody = readRequestBody(exchange);
                TextData textData = TextData.fromJson(requestBody);

                if (textData == null || textData.text() == null || textData.text().isBlank()) {
                    sendResponse(exchange, 400, "{\"error\": \"Invalid request body\"}");
                    return;
                }

                SentimentResult result = analyzeSentiment(textData.text());
                String response = result.toJson();

                sendResponse(exchange, 200, response);
            } catch (Exception e) {
                sendResponse(exchange, 500, "{\"error\": \"Internal server error\"}");
                e.printStackTrace();
            }
        }

        private String readRequestBody(HttpExchange exchange) throws IOException {
            try (InputStream is = exchange.getRequestBody()) {
                return new String(is.readAllBytes(), StandardCharsets.UTF_8);
            }
        }

        private void sendResponse(HttpExchange exchange, int statusCode, String response) throws IOException {
            exchange.getResponseHeaders().set("Content-Type", "application/json");
            exchange.sendResponseHeaders(statusCode, response.length());
            try (OutputStream os = exchange.getResponseBody()) {
                os.write(response.getBytes(StandardCharsets.UTF_8));
            }
        }

        private SentimentResult analyzeSentiment(String text) {
            // Simple sentiment analysis based on positive and negative word counts
            Map<String, Integer> wordScores = new HashMap<>();

            // Positive words
            wordScores.put("good", 1);
            wordScores.put("great", 2);
            wordScores.put("excellent", 2);
            wordScores.put("happy", 1);
            wordScores.put("love", 2);
            wordScores.put("wonderful", 2);

            // Negative words
            wordScores.put("bad", -1);
            wordScores.put("terrible", -2);
            wordScores.put("awful", -2);
            wordScores.put("sad", -1);
            wordScores.put("hate", -2);
            wordScores.put("horrible", -2);

            int score = 0;
            String[] words = text.toLowerCase().split("\\W+");

            for (String word : words) {
                score += wordScores.getOrDefault(word, 0);
            }

            SentimentType sentimentType;
            if (score > 0) {
                sentimentType = SentimentType.POSITIVE;
            } else if (score < 0) {
                sentimentType = SentimentType.NEGATIVE;
            } else {
                sentimentType = SentimentType.NEUTRAL;
            }

            return new SentimentResult(sentimentType, score, text.length());
        }
    }
}
