    public static TextData fromJson(String json) {
        // Simple JSON parsing using pattern matching
        var pattern = Pattern.compile("\\{\\s*\"text\"\\s*:\\s*\"([^\"]+)\"\\s*\\}");
        var matcher = pattern.matcher(json);

        if (matcher.find()) {
            return new TextData(matcher.group(1));
        }
        return null;
    }
