Here's a Rust program that implements a WebSocket chat server with the specifications you requested:

```rust
use std::collections::HashMap;
use std::fs::{File, OpenOptions};
use std::io::{BufReader, BufWriter, Read, Write};
use std::path::Path;
use std::sync::Arc;

use futures_util::{SinkExt, StreamExt};
use tokio::net::{TcpListener, TcpStream};
use tokio::sync::{mpsc, Mutex};
use tokio_tungstenite::{accept_async, tungstenite::Message};
use serde::{Deserialize, Serialize};
use chrono::Utc;

// Maximum number of clients
const MAX_CLIENTS: usize = 100;
const HISTORY_FILE: &str = "chat_history.json";

#[derive(Serialize, Deserialize, Debug, Clone)]
struct ChatMessage {
    from: String,
    to: Option<String>, // None means broadcast to all
    content: String,
    timestamp: String,
}

type ClientMap = Arc<Mutex<HashMap<String, mpsc::Sender<Message>>>>;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let addr = "127.0.0.1:8080";
    let listener = TcpListener::bind(addr).await?;

    println!("WebSocket server started on: {}", addr);

    let clients: ClientMap = Arc::new(Mutex::new(HashMap::new()));

    // Load chat history
    let history = load_chat_history().unwrap_or_else(|_| Vec::new());
    let history = Arc::new(Mutex::new(history));

    while let Ok((stream, addr)) = listener.accept().await {
        let client_count = clients.lock().await.len();
        if client_count >= MAX_CLIENTS {
            println!("Maximum client connection limit reached. Rejecting new connection.");
            continue;
        }

        println!("New connection: {}", addr);
        let clients_clone = clients.clone();
        let history_clone = history.clone();

        tokio::spawn(async move {
            if let Err(e) = handle_connection(stream, clients_clone, history_clone).await {
                println!("Error processing connection: {}", e);
            }
        });
    }

    Ok(())
}

async fn handle_connection(
    stream: TcpStream,
    clients: ClientMap,
    history: Arc<Mutex<Vec<ChatMessage>>>,
) -> Result<(), Box<dyn std::error::Error>> {
    let addr = stream.peer_addr()?;
    let ws_stream = accept_async(stream).await?;

    let (mut ws_sender, mut ws_receiver) = ws_stream.split();

    // Create a channel for this client
    let (tx, mut rx) = mpsc::channel::<Message>(100);

    let mut username = String::new();

    // First message should be the username
    if let Some(Ok(msg)) = ws_receiver.next().await {
        if let Message::Text(name) = msg {
            username = name.trim().to_string();

            // Register the client
            clients.lock().await.insert(username.clone(), tx);

            // Send welcome message
            let welcome = Message::Text(format!("Welcome {}! You are connected to the chat server.", username));
            ws_sender.send(welcome).await?;

            // Send chat history to the new client
            let history_guard = history.lock().await;
            for msg in history_guard.iter() {
                let history_msg = Message::Text(serde_json::to_string(msg)?);
                ws_sender.send(history_msg).await?;
            }
        } else {
            return Err("First message must be a username".into());
        }
    }

    // Handle outgoing messages in a separate task
    let outgoing_task = tokio::spawn(async move {
        while let Some(msg) = rx.recv().await {
            if let Err(e) = ws_sender.send(msg).await {
                println!("Error sending message: {}", e);
                break;
            }
        }
    });

    // Handle incoming messages
    while let Some(result) = ws_receiver.next().await {
        match result {
            Ok(msg) => {
                match msg {
                    Message::Text(text) => {
                        // Parse incoming message
                        let chat_msg: Result<ChatMessage, serde_json::Error> = serde_json::from_str(&text);

                        match chat_msg {
                            Ok(mut chat_msg) => {
                                // Set the sender's username and timestamp
                                chat_msg.from = username.clone();
                                chat_msg.timestamp = Utc::now().to_rfc3339();

                                // Store message in history
                                {
                                    let mut history_guard = history.lock().await;
                                    history_guard.push(chat_msg.clone());
                                    save_chat_history(&history_guard)?;
                                }

                                let json_msg = serde_json::to_string(&chat_msg)?;

                                // Distribute the message
                                let clients_guard = clients.lock().await;

                                if let Some(recipient) = &chat_msg.to {
                                    // Direct message to specific user
                                    if let Some(recipient_tx) = clients_guard.get(recipient) {
                                        if let Err(e) = recipient_tx.send(Message::Text(json_msg.clone())).await {
                                            println!("Failed to send message to {}: {}", recipient, e);
                                        }
                                    }

                                    // Also send a copy to the sender
                                    if let Some(sender_tx) = clients_guard.get(&username) {
                                        if let Err(e) = sender_tx.send(Message::Text(json_msg)).await {
                                            println!("Failed to send message to sender {}: {}", username, e);
                                        }
                                    }
                                } else {
                                    // Broadcast to all clients
                                    for (client_name, client_tx) in clients_guard.iter() {
                                        if let Err(e) = client_tx.send(Message::Text(json_msg.clone())).await {
                                            println!("Failed to send message to {}: {}", client_name, e);
                                        }
                                    }
                                }
                            },
                            Err(e) => {
                                println!("Invalid message format: {}", e);
                                let error_msg = Message::Text(format!("Error: Invalid message format: {}", e));
                                if let Some(client_tx) = clients.lock().await.get(&username) {
                                    let _ = client_tx.send(error_msg).await;
                                }
                            }
                        }
                    },
                    Message::Close(_) => {
                        break;
                    },
                    _ => {}
                }
            },
            Err(e) => {
                println!("Error receiving message from {}: {}", addr, e);
                break;
            }
        }
    }

    // User disconnected, clean up
    println!("{} disconnected", username);
    clients.lock().await.remove(&username);

    // Cancel the outgoing task
    outgoing_task.abort();

    Ok(())
}

fn load_chat_history() -> Result<Vec<ChatMessage>, Box<dyn std::error::Error>> {
    if !Path::new(HISTORY_FILE).exists() {
        return Ok(Vec::new());
    }

    let file = File::open(HISTORY_FILE)?;
    let mut reader = BufReader::new(file);
    let mut contents = String::new();
    reader.read_to_string(&mut contents)?;

    let history: Vec<ChatMessage> = serde_json::from_str(&contents)?;
    Ok(history)
}

fn save_chat_history(history: &[ChatMessage]) -> Result<(), Box<dyn std::error::Error>> {
    let file = OpenOptions::new()
        .write(true)
        .create(true)
        .truncate(true)
        .open(HISTORY_FILE)?;

    let mut writer = BufWriter::new(file);
    let json = serde_json::to_string_pretty(history)?;
    writer.write_all(json.as_bytes())?;

    Ok(())
}
