I'll create a Java service that enforces data retention policies as requested:

```java
package com.retention.service;

import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.time.LocalDateTime;
import java.util.HashMap;
import java.util.Map;
import java.util.Properties;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import com.mongodb.client.MongoClient;
import com.mongodb.client.MongoClients;
import com.mongodb.client.MongoDatabase;

public class DataRetentionService {
    private static final Logger logger = LoggerFactory.getLogger(DataRetentionService.class);

    private final Map<String, RetentionPolicy> retentionPolicies = new HashMap<>();
    private final Properties sqlConfig;
    private final Properties noSqlConfig;
    private final ScheduledExecutorService scheduler;

    public DataRetentionService(Properties sqlConfig, Properties noSqlConfig) {
        this.sqlConfig = sqlConfig;
        this.noSqlConfig = noSqlConfig;
        this.scheduler = Executors.newScheduledThreadPool(2);
    }

    public void addRetentionPolicy(String tableName, String databaseType, RetentionPolicy policy) {
        retentionPolicies.put(tableName + ":" + databaseType, policy);
        logger.info("Added retention policy for {}: {}", tableName, policy);
    }

    public void removeRetentionPolicy(String tableName, String databaseType) {
        retentionPolicies.remove(tableName + ":" + databaseType);
        logger.info("Removed retention policy for {}", tableName);
    }

    public void start() {
        scheduler.scheduleAtFixedRate(this::executeRetentionPolicies, 0, 24, TimeUnit.HOURS);
        logger.info("Data retention service started");
    }

    public void stop() {
        scheduler.shutdown();
        logger.info("Data retention service stopped");
    }

    private void executeRetentionPolicies() {
        retentionPolicies.forEach((key, policy) -> {
            String[] parts = key.split(":");
            String tableName = parts[0];
            String dbType = parts[1];

            try {
                switch (dbType) {
                    case "SQL" -> executeSqlRetentionPolicy(tableName, policy);
                    case "MONGODB" -> executeMongoDbRetentionPolicy(tableName, policy);
                    default -> logger.warn("Unsupported database type: {}", dbType);
                }
            } catch (Exception e) {
                logger.error("Failed to execute retention policy for {}: {}", tableName, e.getMessage(), e);
            }
        });
    }

    private void executeSqlRetentionPolicy(String tableName, RetentionPolicy policy) throws Exception {
        String url = sqlConfig.getProperty("jdbc.url");
        String username = sqlConfig.getProperty("jdbc.username");
        String password = sqlConfig.getProperty("jdbc.password");

        try (Connection conn = DriverManager.getConnection(url, username, password)) {
            LocalDateTime cutoffDate = LocalDateTime.now().minus(policy.duration(), policy.unit());

            String sql = switch (policy.dateFieldType()) {
                case TIMESTAMP -> "DELETE FROM " + tableName + " WHERE " + policy.dateField() + " < ?";
                case DATE -> "DELETE FROM " + tableName + " WHERE " + policy.dateField() + " < ?::date";
                case EPOCH -> "DELETE FROM " + tableName + " WHERE " + policy.dateField() + " < ?";
                default -> throw new IllegalArgumentException("Unsupported date field type: " + policy.dateFieldType());
            };

            try (PreparedStatement stmt = conn.prepareStatement(sql)) {
                switch (policy.dateFieldType()) {
                    case TIMESTAMP -> stmt.setTimestamp(1, java.sql.Timestamp.valueOf(cutoffDate));
                    case DATE -> stmt.setDate(1, java.sql.Date.valueOf(cutoffDate.toLocalDate()));
                    case EPOCH -> stmt.setLong(1, cutoffDate.toEpochSecond(java.time.ZoneOffset.UTC));
                }

                int rowsAffected = stmt.executeUpdate();
                logger.info("Deleted {} records from {} based on retention policy", rowsAffected, tableName);
            }
        }
    }

    private void executeMongoDbRetentionPolicy(String collectionName, RetentionPolicy policy) {
        String connectionString = noSqlConfig.getProperty("mongodb.uri");
        String databaseName = noSqlConfig.getProperty("mongodb.database");

        try (MongoClient mongoClient = MongoClients.create(connectionString)) {
            MongoDatabase database = mongoClient.getDatabase(databaseName);
            LocalDateTime cutoffDate = LocalDateTime.now().minus(policy.duration(), policy.unit());

            String dateField = policy.dateField();
            Object cutoffValue = switch (policy.dateFieldType()) {
                case TIMESTAMP, DATE -> java.util.Date.from(cutoffDate.toInstant(java.time.ZoneOffset.UTC));
                case EPOCH -> cutoffDate.toEpochSecond(java.time.ZoneOffset.UTC);
                case ISO_STRING -> cutoffDate.toString();
                default -> throw new IllegalArgumentException("Unsupported date field type: " + policy.dateFieldType());
            };

            com.mongodb.client.model.DeleteOptions options = new com.mongodb.client.model.DeleteOptions();
            org.bson.Document filter = new org.bson.Document(dateField, new org.bson.Document("$lt", cutoffValue));

            long deletedCount = database.getCollection(collectionName).deleteMany(filter, options).getDeletedCount();
            logger.info("Deleted {} documents from {} based on retention policy", deletedCount, collectionName);
        }
    }

    public record RetentionPolicy(
        long duration,
        TimeUnit unit,
        String dateField,
        DateFieldType dateFieldType
    ) {
        public RetentionPolicy {
            if (duration <= 0) {
                throw new IllegalArgumentException("Duration must be positive");
            }
            if (dateField == null || dateField.isEmpty()) {
                throw new IllegalArgumentException("Date field must not be empty");
            }
        }
    }

    public enum DateFieldType {
        TIMESTAMP,
        DATE,
        EPOCH,
        ISO_STRING
    }
}
