package com.retention.service;

import java.time.temporal.ChronoUnit;
import java.util.Properties;
import java.util.concurrent.TimeUnit;

public class RetentionServiceConfig {
    private final Properties properties = new Properties();

    public RetentionServiceConfig() {
        // Set defaults
        properties.setProperty("execution.interval.hours", "24");
        properties.setProperty("execution.threads", "2");
    }

    public void loadFromFile(String filePath) throws Exception {
        Properties fileProps = new Properties();
        fileProps.load(new java.io.FileInputStream(filePath));
        properties.putAll(fileProps);
    }

    public int getExecutionIntervalHours() {
        return Integer.parseInt(properties.getProperty("execution.interval.hours"));
    }

    public int getThreadPoolSize() {
        return Integer.parseInt(properties.getProperty("execution.threads"));
    }

    public RetentionPolicy buildRetentionPolicy(String tableName) {
        String prefix = "retention." + tableName + ".";

        if (!properties.containsKey(prefix + "duration")) {
            return null;
        }

        long duration = Long.parseLong(properties.getProperty(prefix + "duration"));
        String unitStr = properties.getProperty(prefix + "unit", "DAYS");
        String dateField = properties.getProperty(prefix + "dateField", "created_at");
        String dateFieldTypeStr = properties.getProperty(prefix + "dateFieldType", "TIMESTAMP");

        TimeUnit unit = switch (unitStr) {
            case "DAYS" -> TimeUnit.DAYS;
            case "HOURS" -> TimeUnit.HOURS;
            case "MINUTES" -> TimeUnit.MINUTES;
            case "SECONDS" -> TimeUnit.SECONDS;
            case "YEARS" when duration > 0 -> {
                // Convert years to days for TimeUnit compatibility
                duration = duration * 365;
                yield TimeUnit.DAYS;
            }
            case "MONTHS" when duration > 0 -> {
                // Convert months to days for TimeUnit compatibility
                duration = duration * 30;
                yield TimeUnit.DAYS;
            }
            default -> throw new IllegalArgumentException("Unsupported time unit: " + unitStr);
        };

        DataRetentionService.DateFieldType dateFieldType = switch (dateFieldTypeStr) {
            case "TIMESTAMP" -> DataRetentionService.DateFieldType.TIMESTAMP;
            case "DATE" -> DataRetentionService.DateFieldType.DATE;
            case "EPOCH" -> DataRetentionService.DateFieldType.EPOCH;
            case "ISO_STRING" -> DataRetentionService.DateFieldType.ISO_STRING;
            default -> throw new IllegalArgumentException("Unsupported date field type: " + dateFieldTypeStr);
        };

        return new DataRetentionService.RetentionPolicy(duration, unit, dateField, dateFieldType);
    }

    public record RetentionPolicy(long duration, TimeUnit unit, String dateField, 
                                  DataRetentionService.DateFieldType dateFieldType) {}
}
