Here's a Rust command-line application that migrates log files from `.log` to `.bin` format using `bincode` with concurrent processing:

```rust
use anyhow::{Context, Result};
use serde::{Deserialize, Serialize};
use std::path::{Path, PathBuf};
use structopt::StructOpt;
use tokio::fs::{self, File};
use tokio::io::{AsyncReadExt, AsyncWriteExt};
use tokio::task;

#[derive(Debug, StructOpt)]
#[structopt(name = "log-migrator", about = "Migrates .log files to .bin format")]
struct Opt {
    /// Directory containing log files to migrate
    #[structopt(parse(from_os_str))]
    input_dir: PathBuf,
}

#[derive(Serialize, Deserialize, Debug)]
struct LogEntry {
    timestamp: u64,
    level: String,
    message: String,
    // Add other fields as needed for your log format
}

#[derive(Serialize, Deserialize, Debug)]
struct LogFile {
    entries: Vec<LogEntry>,
    // Add other fields as needed
}

async fn process_file(log_path: PathBuf) -> Result<()> {
    println!("Processing: {}", log_path.display());

    // Read the file content
    let mut file = File::open(&log_path).await
        .with_context(|| format!("Failed to open file: {}", log_path.display()))?;
    let mut content = String::new();
    file.read_to_string(&mut content).await
        .with_context(|| format!("Failed to read file: {}", log_path.display()))?;

    // Deserialize from the log format
    let log_data: LogFile = serde_json::from_str(&content)
        .with_context(|| format!("Failed to deserialize log file: {}", log_path.display()))?;

    // Serialize to binary format
    let binary_data = bincode::serialize(&log_data)
        .with_context(|| format!("Failed to serialize to binary: {}", log_path.display()))?;

    // Create output path with .bin extension
    let mut output_path = log_path.clone();
    output_path.set_extension("bin");

    // Write the binary data
    let mut output_file = File::create(&output_path).await
        .with_context(|| format!("Failed to create output file: {}", output_path.display()))?;
    output_file.write_all(&binary_data).await
        .with_context(|| format!("Failed to write binary data to: {}", output_path.display()))?;

    println!("Converted: {} -> {}", log_path.display(), output_path.display());
    Ok(())
}

#[tokio::main]
async fn main() -> Result<()> {
    let opt = Opt::from_args();

    // Read all entries in the directory
    let mut entries = fs::read_dir(opt.input_dir).await
        .context("Failed to read input directory")?;

    let mut tasks = Vec::new();

    // Process each .log file concurrently
    while let Some(entry) = entries.next_entry().await.context("Failed to read directory entry")? {
        let path = entry.path();
        if path.is_file() && path.extension().map_or(false, |ext| ext == "log") {
            // Spawn a task for each log file
            let handle = task::spawn(async move {
                if let Err(e) = process_file(path.clone()).await {
                    eprintln!("Error processing {}: {}", path.display(), e);
                }
            });
            tasks.push(handle);
        }
    }

    // Wait for all tasks to complete
    for task in tasks {
        task.await?;
    }

    println!("Migration completed successfully");
    Ok(())
}
