Here's a Java-based WebSocket server application using JDK 11:

```java:WebSocketServer.java
package com.example.websocket;

import java.net.InetSocketAddress;
import java.nio.ByteBuffer;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ThreadPoolExecutor;

import org.java_websocket.WebSocket;
import org.java_websocket.handshake.ClientHandshake;
import org.java_websocket.server.WebSocketServer;

public class RealTimeWebSocketServer extends WebSocketServer {

    private static final int PORT = 8080;
    private final Map<WebSocket, String> clients = new ConcurrentHashMap<>();
    private final ThreadPoolExecutor executor = (ThreadPoolExecutor) Executors.newCachedThreadPool();

    public RealTimeWebSocketServer() {
        super(new InetSocketAddress(PORT));
        System.setProperty("java.util.concurrent.ForkJoinPool.common.parallelism", 
                           String.valueOf(Runtime.getRuntime().availableProcessors()));
    }

    @Override
    public void onOpen(WebSocket conn, ClientHandshake handshake) {
        String clientId = generateClientId();
        clients.put(conn, clientId);

        System.out.println("New connection established: " + clientId);

        // Send welcome message to new client
        conn.send("Welcome to the WebSocket server! Your ID: " + clientId);

        // Broadcast new client connection to all clients
        broadcast("New client connected: " + clientId);
    }

    @Override
    public void onClose(WebSocket conn, int code, String reason, boolean remote) {
        String clientId = clients.get(conn);
        clients.remove(conn);

        System.out.println("Connection closed for client: " + clientId);
        broadcast("Client disconnected: " + clientId);
    }

    @Override
    public void onMessage(WebSocket conn, String message) {
        String clientId = clients.get(conn);
        System.out.println("Message from " + clientId + ": " + message);

        // Process message asynchronously
        CompletableFuture.supplyAsync(() -> processMessage(message), executor)
            .thenAccept(result -> {
                // Broadcast processed message to all clients
                broadcast("Client " + clientId + " says: " + result);
            })
            .exceptionally(ex -> {
                System.err.println("Error processing message: " + ex.getMessage());
                conn.send("Error processing your message");
                return null;
            });
    }

    @Override
    public void onMessage(WebSocket conn, ByteBuffer message) {
        String clientId = clients.get(conn);

        // Handle binary messages asynchronously
        CompletableFuture.supplyAsync(() -> processBinaryMessage(message), executor)
            .thenAccept(result -> {
                conn.send("Binary message processed successfully");
            })
            .exceptionally(ex -> {
                System.err.println("Error processing binary message: " + ex.getMessage());
                conn.send("Error processing your binary message");
                return null;
            });
    }

    @Override
    public void onError(WebSocket conn, Exception ex) {
        String clientId = conn != null ? clients.get(conn) : "unknown";
        System.err.println("Error occurred for client " + clientId + ": " + ex.getMessage());
        ex.printStackTrace();

        if (conn != null) {
            conn.close();
        }
    }

    @Override
    public void onStart() {
        System.out.println("WebSocket server started on port: " + PORT);
        setConnectionLostTimeout(30);
    }

    private String generateClientId() {
        return "client-" + System.nanoTime();
    }

    private String processMessage(String message) {
        // Simulate resource-intensive processing
        try {
            Thread.sleep(100);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }

        // Use Java 11 String methods for processing
        return message.strip().transform(this::enhanceMessage);
    }

    private String enhanceMessage(String message) {
        // Demonstrate Java 11 String methods
        if (message.isBlank()) {
            return "Empty message received";
        }

        return message.lines()
                .map(String::trim)
                .reduce((a, b) -> a + " " + b)
                .orElse("");
    }

    private ByteBuffer processBinaryMessage(ByteBuffer buffer) {
        // Process binary message
        // This is a placeholder for actual binary processing
        return buffer;
    }

    public static void main(String[] args) {
        RealTimeWebSocketServer server = new RealTimeWebSocketServer();
        server.start();
    }
}
