Here's a Java application that fetches and analyzes stock market data in real-time:

```java
package com.stockmarket;

import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;
import java.time.Duration;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.DoubleSummaryStatistics;
import java.util.List;
import java.util.logging.FileHandler;
import java.util.logging.Level;
import java.util.logging.Logger;
import java.util.logging.SimpleFormatter;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;

public class StockMarketAnalyzer {
    private static final Logger LOGGER = Logger.getLogger(StockMarketAnalyzer.class.getName());
    private static final String API_KEY = "YOUR_API_KEY"; // Replace with your actual API key
    private static final String DB_URL = "jdbc:sqlite:stockmarket.db";
    private static final HttpClient httpClient = HttpClient.newBuilder()
            .version(HttpClient.Version.HTTP_2)
            .connectTimeout(Duration.ofSeconds(10))
            .build();
    private static final ObjectMapper objectMapper = new ObjectMapper();

    static {
        try {
            FileHandler fileHandler = new FileHandler("stockmarket.log", true);
            fileHandler.setFormatter(new SimpleFormatter());
            LOGGER.addHandler(fileHandler);
            LOGGER.setLevel(Level.INFO);
        } catch (IOException e) {
            LOGGER.severe("Failed to initialize logger: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        // Initialize database
        initializeDatabase();

        // Example: Fetch and analyze data for Apple Inc.
        String symbol = "AAPL";
        String timeFrame = "1d"; // 1 day

        try {
            List<StockPrice> stockPrices = fetchStockData(symbol, timeFrame);
            if (!stockPrices.isEmpty()) {
                StockAnalysis analysis = analyzeStockData(symbol, stockPrices);
                saveAnalysisToDatabase(analysis);

                LOGGER.info("Analysis completed for " + symbol + ": " + analysis);
            } else {
                LOGGER.warning("No data retrieved for " + symbol);
            }
        } catch (Exception e) {
            LOGGER.severe("Error processing stock data: " + e.getMessage());
        }
    }

    private static void initializeDatabase() {
        try (Connection conn = getConnection();
             Statement stmt = conn.createStatement()) {

            // Create table for stock analysis results
            String sql = "CREATE TABLE IF NOT EXISTS stock_analysis (" +
                         "id INTEGER PRIMARY KEY AUTOINCREMENT," +
                         "symbol TEXT NOT NULL," +
                         "timestamp TEXT NOT NULL," +
                         "avg_price REAL NOT NULL," +
                         "min_price REAL NOT NULL," +
                         "max_price REAL NOT NULL," +
                         "data_points INTEGER NOT NULL)";

            stmt.execute(sql);
            LOGGER.info("Database initialized successfully");

        } catch (SQLException e) {
            LOGGER.severe("Database initialization failed: " + e.getMessage());
        }
    }

    private static Connection getConnection() throws SQLException {
        return DriverManager.getConnection(DB_URL);
    }

    private static List<StockPrice> fetchStockData(String symbol, String timeFrame) throws IOException, InterruptedException {
        LOGGER.info("Fetching stock data for " + symbol + " with timeframe " + timeFrame);

        // Using Alpha Vantage API as an example
        String apiUrl = "https://www.alphavantage.co/query?function=TIME_SERIES_INTRADAY" +
                        "&symbol=" + symbol +
                        "&interval=5min" +
                        "&apikey=" + API_KEY;

        HttpRequest request = HttpRequest.newBuilder()
                .GET()
                .uri(URI.create(apiUrl))
                .header("Accept", "application/json")
                .build();

        HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

        if (response.statusCode() != 200) {
            LOGGER.warning("API request failed with status code: " + response.statusCode());
            return new ArrayList<>();
        }

        return parseStockData(response.body());
    }

    private static List<StockPrice> parseStockData(String jsonData) throws IOException {
        List<StockPrice> prices = new ArrayList<>();

        JsonNode rootNode = objectMapper.readTree(jsonData);
        JsonNode timeSeriesNode = rootNode.get("Time Series (5min)");

        if (timeSeriesNode == null) {
            LOGGER.warning("No time series data found in API response");
            return prices;
        }

        timeSeriesNode.fields().forEachRemaining(entry -> {
            String timestamp = entry.getKey();
            JsonNode dataNode = entry.getValue();

            try {
                double price = Double.parseDouble(dataNode.get("4. close").asText());
                prices.add(new StockPrice(timestamp, price));
            } catch (NumberFormatException e) {
                LOGGER.warning("Failed to parse price for timestamp " + timestamp);
            }
        });

        LOGGER.info("Parsed " + prices.size() + " data points");
        return prices;
    }

    private static StockAnalysis analyzeStockData(String symbol, List<StockPrice> prices) {
        LOGGER.info("Analyzing stock data for " + symbol);

        DoubleSummaryStatistics stats = prices.stream()
                .mapToDouble(StockPrice::getPrice)
                .summaryStatistics();

        return new StockAnalysis(
                symbol,
                LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME),
                stats.getAverage(),
                stats.getMin(),
                stats.getMax(),
                stats.getCount()
        );
    }

    private static void saveAnalysisToDatabase(StockAnalysis analysis) {
        String sql = "INSERT INTO stock_analysis (symbol, timestamp, avg_price, min_price, max_price, data_points) " +
                     "VALUES (?, ?, ?, ?, ?, ?)";

        try (Connection conn = getConnection();
             PreparedStatement pstmt = conn.prepareStatement(sql)) {

            pstmt.setString(1, analysis.getSymbol());
            pstmt.setString(2, analysis.getTimestamp());
            pstmt.setDouble(3, analysis.getAvgPrice());
            pstmt.setDouble(4, analysis.getMinPrice());
            pstmt.setDouble(5, analysis.getMaxPrice());
            pstmt.setLong(6, analysis.getDataPoints());

            pstmt.executeUpdate();
            LOGGER.info("Analysis saved to database for " + analysis.getSymbol());

        } catch (SQLException e) {
            LOGGER.severe("Failed to save analysis to database: " + e.getMessage());
        }
    }

    // Data classes
    static class StockPrice {
        private final String timestamp;
        private final double price;

        public StockPrice(String timestamp, double price) {
            this.timestamp = timestamp;
            this.price = price;
        }

        public String getTimestamp() {
            return timestamp;
        }

        public double getPrice() {
            return price;
        }
    }

    static class StockAnalysis {
        private final String symbol;
        private final String timestamp;
        private final double avgPrice;
        private final double minPrice;
        private final double maxPrice;
        private final long dataPoints;

        public StockAnalysis(String symbol, String timestamp, double avgPrice, double minPrice, double maxPrice, long dataPoints) {
            this.symbol = symbol;
            this.timestamp = timestamp;
            this.avgPrice = avgPrice;
            this.minPrice = minPrice;
            this.maxPrice = maxPrice;
            this.dataPoints = dataPoints;
        }

        public String getSymbol() {
            return symbol;
        }

        public String getTimestamp() {
            return timestamp;
        }

        public double getAvgPrice() {
            return avgPrice;
        }

        public double getMinPrice() {
            return minPrice;
        }

        public double getMaxPrice() {
            return maxPrice;
        }

        public long getDataPoints() {
            return dataPoints;
        }

        @Override
        public String toString() {
            return "StockAnalysis{" +
                   "symbol='" + symbol + '\'' +
                   ", timestamp='" + timestamp + '\'' +
                   ", avgPrice=" + avgPrice +
                   ", minPrice=" + minPrice +
                   ", maxPrice=" + maxPrice +
                   ", dataPoints=" + dataPoints +
                   '}';
        }
    }
}
