public class CSVProcessorCLI implements Callable<Integer> {

    @Option(names = {"-f", "--file"}, description = "CSV file to process", required = true)
    private File csvFile;

    @Option(names = {"-c", "--config"}, description = "Configuration file for column reordering")
    private File configFile;

