Here's a Rust server implementation that serves static files efficiently using async I/O:

```rust
use std::path::{Path, PathBuf};
use std::sync::Arc;

use bytes::Bytes;
use futures::stream::StreamExt;
use hyper::service::{make_service_fn, service_fn};
use hyper::{Body, Method, Request, Response, Server, StatusCode};
use mime_guess::from_path;
use tokio::fs::File;
use tokio::io::{self, AsyncReadExt};
use tokio_util::codec::{BytesCodec, FramedRead};

const STATIC_DIR: &str = "static";
const BUFFER_SIZE: usize = 8 * 1024; // 8KB chunks for streaming

type Result<T> = std::result::Result<T, Box<dyn std::error::Error + Send + Sync>>;

async fn stream_file(path: PathBuf) -> Result<Response<Body>> {
    // Open the file
    let file = File::open(&path).await?;
    let file_size = file.metadata().await?.len();

    // Get MIME type based on file extension
    let mime_type = from_path(&path)
        .first_or_octet_stream()
        .as_ref()
        .to_string();

    // Stream the file using zero-copy when possible
    let stream = FramedRead::new(file, BytesCodec::new())
        .map(|result| result.map(|bytes| bytes.freeze()));

    let body = Body::wrap_stream(stream);

    // Create response with appropriate headers
    let response = Response::builder()
        .status(StatusCode::OK)
        .header("content-type", mime_type)
        .header("content-length", file_size)
        .body(body)?;

    Ok(response)
}

async fn handle_request(req: Request<Body>) -> Result<Response<Body>> {
    match (req.method(), req.uri().path()) {
        (&Method::GET, path) => {
            // Normalize the path and prevent directory traversal
            let path = path.trim_start_matches('/');
            let mut full_path = PathBuf::from(STATIC_DIR);

            for part in Path::new(path).components() {
                if part.as_os_str() == ".." {
                    return Ok(Response::builder()
                        .status(StatusCode::FORBIDDEN)
                        .body(Body::from("Directory traversal is not allowed"))?);
                }
                full_path.push(part);
            }

            // Serve index.html for root path
            if path.is_empty() || path == "/" {
                full_path.push("index.html");
            }

            // Check if file exists and is a file
            if !full_path.exists() {
                return Ok(Response::builder()
                    .status(StatusCode::NOT_FOUND)
                    .body(Body::from("File not found"))?);
            }

            if full_path.is_dir() {
                full_path.push("index.html");
                if !full_path.exists() {
                    return Ok(Response::builder()
                        .status(StatusCode::NOT_FOUND)
                        .body(Body::from("Directory index not available"))?);
                }
            }

            // Stream the file
            stream_file(full_path).await
        },
        _ => {
            // Return 405 Method Not Allowed for non-GET requests
            Ok(Response::builder()
                .status(StatusCode::METHOD_NOT_ALLOWED)
                .body(Body::from("Method not allowed"))?
            )
        }
    }
}

#[tokio::main]
async fn main() -> Result<()> {
    // Set up the server address
    let addr = ([127, 0, 0, 1], 8080).into();

    // Create a service function that handles each connection
    let service = make_service_fn(|_| async {
        Ok::<_, hyper::Error>(service_fn(handle_request))
    });

    // Create the server
    let server = Server::bind(&addr).serve(service);

    println!("Server running at http://{}", addr);

    // Run the server
    server.await?;

    Ok(())
}
