```rust
// src/main.rs
use async_std::path::PathBuf;
use clap::Parser;
use futures::future::join_all;
use lettre::{
    message::{header, MultiPart, SinglePart},
    transport::smtp::authentication::Credentials,
    Message, SmtpTransport, Transport,
};
use notify::{Config, Event, EventKind, RecommendedWatcher, RecursiveMode, Watcher};
use serde::{Deserialize, Serialize};
use std::{collections::HashMap, path::Path, sync::Arc, time::{SystemTime, UNIX_EPOCH}};
use tokio::{
    fs,
    sync::{mpsc, Mutex},
    time::{self, Duration},
};

// CLI Arguments structure
#[derive(Parser, Debug)]
#[clap(author, version, about)]
struct Args {
    /// Path to configuration file
    #[clap(short, long, default_value = "config.toml")]
    config: String,
}

// Configuration structure
#[derive(Debug, Deserialize, Serialize)]
struct Config {
    directories: Vec<String>,
    email: EmailConfig,
    polling_interval_ms: Option<u64>,
}

#[derive(Debug, Deserialize, Serialize)]
struct EmailConfig {
    smtp_server: String,
    smtp_port: u16,
    username: String,
    password: String,
    from_email: String,
    to_email: String,
}

// File event structure
#[derive(Debug)]
struct FileEvent {
    path: PathBuf,
    timestamp: u64,
}

// Initialize the file watcher
async fn watch_directory(
    path: String,
    tx: mpsc::Sender<FileEvent>,
    polling_interval: Duration,
) -> notify::Result<()> {
    let path = Path::new(&path);

    // Store already seen files to avoid duplicate notifications
    let seen_files = Arc::new(Mutex::new(HashMap::<String, u64>::new()));

    // Create initial snapshot of existing files
    let initial_files = fs::read_dir(path).await?;
    let mut entries = Vec::new();

    let mut seen = seen_files.lock().await;
    let mut entry = initial_files.next_entry().await?;
    while let Some(e) = entry {
        if let Ok(metadata) = e.metadata().await {
            if metadata.is_file() {
                if let Some(path_str) = e.path().to_str() {
                    seen.insert(path_str.to_string(), 1);
                }
            }
        }
        entry = initial_files.next_entry().await?;
    }
    drop(seen);

    // Create watcher with custom configuration for minimal latency
    let (watcher_tx, mut watcher_rx) = mpsc::channel(100);
    let mut watcher = RecommendedWatcher::new(
        move |res: notify::Result<Event>| {
            if let Ok(event) = res {
                if let EventKind::Create(_) = event.kind {
                    for path in event.paths {
                        let _ = watcher_tx.try_send(path);
                    }
                }
            }
        },
        Config::default().with_poll_interval(polling_interval),
    )?;

    // Start watching the directory
    watcher.watch(path, RecursiveMode::Recursive)?;

    // Using a separate task to check for new files periodically as a backup
    let seen_files_clone = Arc::clone(&seen_files);
    let path_clone = path.to_path_buf();
    let tx_clone = tx.clone();

    tokio::spawn(async move {
        let mut interval = time::interval(polling_interval);
        loop {
            interval.tick().await;

            if let Ok(entries) = fs::read_dir(&path_clone).await {
                let mut files = vec![];
                let mut entry_result = entries.next_entry().await;

                while let Ok(Some(entry)) = entry_result {
                    if let Ok(metadata) = entry.metadata().await {
                        if metadata.is_file() {
                            files.push(entry.path());
                        }
                    }
                    entry_result = entries.next_entry().await;
                }

                let mut seen = seen_files_clone.lock().await;
                for file_path in files {
                    if let Some(path_str) = file_path.to_str() {
                        if !seen.contains_key(path_str) {
                            // New file detected, send notification
                            let timestamp = SystemTime::now()
                                .duration_since(UNIX_EPOCH)
                                .unwrap()
                                .as_secs();

                            seen.insert(path_str.to_string(), timestamp);

                            let _ = tx_clone.send(FileEvent {
                                path: async_std::path::PathBuf::from(path_str),
                                timestamp,
                            }).await;
                        }
                    }
                }
            }
        }
    });

    // Process events from watcher channel
    while let Some(path) = watcher_rx.recv().await {
        let path_str = path.to_str().unwrap_or_default().to_string();
        let mut seen = seen_files.lock().await;

        if !seen.contains_key(&path_str) {
            let timestamp = SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .unwrap()
                .as_secs();

            seen.insert(path_str.clone(), timestamp);

            let _ = tx.send(FileEvent {
                path: async_std::path::PathBuf::from(path_str),
                timestamp,
            }).await;
        }
    }

    Ok(())
}

// Send email notification
async fn send_email_notification(event: FileEvent, config: &EmailConfig) -> Result<(), Box<dyn std::error::Error>> {
    let timestamp = chrono::DateTime::<chrono::Utc>::from(
        std::time::UNIX_EPOCH + std::time::Duration::from_secs(event.timestamp)
    );

    let formatted_time = timestamp.format("%Y-%m-%d %H:%M:%S UTC").to_string();
    let file_name = event.path.file_name().unwrap_or_default().to_string_lossy();
    let file_path = event.path.to_string_lossy();

    let email = Message::builder()
        .from(config.from_email.parse()?)
        .to(config.to_email.parse()?)
        .subject("New File Detected Alert")
        .multipart(
            MultiPart::alternative()
                .singlepart(
                    SinglePart::builder()
                        .header(header::ContentType::TEXT_PLAIN)
                        .body(format!(
                            "New file detected!\n\nFile name: {}\nPath: {}\nTime: {}",
                            file_name, file_path, formatted_time
                        ))
                )
                .singlepart(
                    SinglePart::builder()
                        .header(header::ContentType::TEXT_HTML)
                        .body(format!(
                            r#"<html>
                                <body>
                                    <h2>New File Detected!</h2>
                                    <p><strong>File name:</strong> {}</p>
                                    <p><strong>Path:</strong> {}</p>
                                    <p><strong>Time:</strong> {}</p>
                                </body>
                            </html>"#,
                            file_name, file_path, formatted_time
                        ))
                )
        )?;

    let creds = Credentials::new(config.username.clone(), config.password.clone());

    let mailer = SmtpTransport::relay(&config.smtp_server)?
        .port(config.smtp_port)
        .credentials(creds)
        .build();

    mailer.send(&email)?;
    println!("Email notification sent for file: {}", file_path);

    Ok(())
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args = Args::parse();

    // Read configuration
    let config_content = fs::read_to_string(&args.config).await?;
    let config: Config = toml::from_str(&config_content)?;

    // Create channel for file events
    let (tx, mut rx) = mpsc::channel::<FileEvent>(100);

    // Calculate polling interval with default of 50ms for minimal latency
    let polling_interval = Duration::from_millis(config.polling_interval_ms.unwrap_or(50));

    // Start watching all directories
    let mut watch_tasks = vec![];
    for dir in &config.directories {
        let dir_clone = dir.clone();
        let tx_clone = tx.clone();
        let task = tokio::spawn(async move {
            if let Err(e) = watch_directory(dir_clone, tx_clone, polling_interval).await {
                eprintln!("Error watching directory: {}", e);
            }
        });
        watch_tasks.push(task);
    }

    // Process file events and send notifications
    tokio::spawn(async move {
        while let Some(event) = rx.recv().await {
            println!("New file detected: {:?}", event.path);

            match send_email_notification(event, &config.email).await {
                Ok(_) => {},
                Err(e) => eprintln!("Failed to send email notification: {}", e),
            }
        }
    });

    // Wait for all watch tasks to complete (they run indefinitely)
    join_all(watch_tasks).await;

    Ok(())
}
