```rust
use std::error::Error;
use std::fs::{File, OpenOptions};
use std::io::Write;
use std::path::Path;
use std::time::{SystemTime, UNIX_EPOCH};
use tokio::time::{self, Duration};
use sysinfo::{System, SystemExt, ProcessorExt, DiskExt};
use chrono::{DateTime, Utc};

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    println!("Server Monitoring Tool");
    println!("Collecting system resource usage every minute");

    let csv_path = "system_monitoring.csv";

    // Initialize CSV if it doesn't exist
    if !Path::new(csv_path).exists() {
        let mut file = File::create(csv_path)?;
        writeln!(file, "timestamp,cpu_usage_percent,memory_used_mb,memory_total_mb,storage_used_mb,storage_total_mb")?;
    }

    let mut interval = time::interval(Duration::from_secs(60));

    // Initialize system info collector
    let mut system = System::new_all();

    loop {
        interval.tick().await;

        // Refresh system information
        system.refresh_all();

        match collect_and_log_metrics(&mut system, csv_path).await {
            Ok(_) => println!("Metrics collected successfully at {}", get_current_time()),
            Err(e) => eprintln!("Error collecting metrics: {}", e),
        }
    }
}

async fn collect_and_log_metrics(system: &mut System, csv_path: &str) -> Result<(), Box<dyn Error>> {
    // Update all system information
    system.refresh_all();

    // Get the current timestamp
    let timestamp = get_current_time();

    // CPU usage (average across all cores)
    let cpu_usage = system.processors().iter()
        .map(|p| p.cpu_usage())
        .sum::<f32>() / system.processors().len() as f32;

    // Memory usage
    let memory_used = system.used_memory() / 1024 / 1024; // MB
    let memory_total = system.total_memory() / 1024 / 1024; // MB

    // Storage usage (summing across all disks)
    let mut storage_used = 0;
    let mut storage_total = 0;

    for disk in system.disks() {
        storage_used += disk.available_space() / (1024 * 1024); // MB
        storage_total += disk.total_space() / (1024 * 1024); // MB
    }

    // Append data to CSV
    let mut file = OpenOptions::new()
        .append(true)
        .open(csv_path)?;

    writeln!(
        file,
        "{},{:.2},{},{},{},{}",
        timestamp, cpu_usage, memory_used, memory_total, storage_used, storage_total
    )?;

    Ok(())
}

fn get_current_time() -> String {
    let now = SystemTime::now();
    let since_epoch = now.duration_since(UNIX_EPOCH)
        .expect("Time went backwards");

    let datetime = DateTime::<Utc>::from(now);
    datetime.format("%Y-%m-%d %H:%M:%S").to_string()
}
