        server.start();
        System.out.println("Server started on port " + SERVER_PORT);
        System.out.println("Monitor a Java process by accessing: http://localhost:" + SERVER_PORT + 
                          MONITORING_PATH + "?" + PROCESS_ID_PARAM + "=<pid>");
    }

    private static void handleMonitoringRequest(HttpExchange exchange) throws IOException {
        // Parse query parameters to get PID
        String query = exchange.getRequestURI().getQuery();
        String pidStr = extractQueryParam(query, PROCESS_ID_PARAM);

        if (pidStr == null || pidStr.isEmpty()) {
            sendErrorResponse(exchange, 400, "Missing process ID. Use ?pid=<process_id>");
            return;
        }

        try {
            int pid = Integer.parseInt(pidStr);
            String metricsJson = collectProcessMetrics(pid);

            // Send JSON response
            exchange.getResponseHeaders().set("Content-Type", "application/json");
            exchange.sendResponseHeaders(200, metricsJson.length());
            try (OutputStream os = exchange.getResponseBody()) {
                os.write(metricsJson.getBytes());
            }
        } catch (NumberFormatException e) {
            sendErrorResponse(exchange, 400, "Invalid process ID format");
        } catch (IOException e) {
            sendErrorResponse(exchange, 500, "Error collecting metrics: " + e.getMessage());
        }
    }

    private static String collectProcessMetrics(int pid) throws IOException {
        // Use JDK 11 HTTP Client to connect to the JMX service of the target Java process
        HttpClient httpClient = HttpClient.newBuilder()
                .version(HttpClient.Version.HTTP_2)
                .connectTimeout(Duration.ofSeconds(5))
                .build();

        // Create a JMX connection to the process
        AtomicReference<Double> cpuUsage = new AtomicReference<>(0.0);
        AtomicReference<Long> usedMemory = new AtomicReference<>(0L);
        AtomicReference<Long> maxMemory = new AtomicReference<>(0L);

        try {
            // In a real implementation, you would use JMX to connect to the process
            // For demonstration, we'll use the local system metrics
            OperatingSystemMXBean osBean = (OperatingSystemMXBean) ManagementFactory.getOperatingSystemMXBean();

            // CPU usage (system-wide as an example)
            cpuUsage.set(osBean.getSystemCpuLoad() * 100);

            // Memory usage (system-wide as an example)
            usedMemory.set(osBean.getTotalMemorySize() - osBean.getFreeMemorySize());
            maxMemory.set(osBean.getTotalMemorySize());

            // In a real implementation, filter metrics for the specific PID
        } catch (Exception e) {
            throw new IOException("Failed to connect to process: " + e.getMessage());
        }

        // Format metrics as JSON
        return String.format(
                "{\"processId\":%d,\"metrics\":{\"cpuUsage\":%.2f,\"memoryUsed\":%d,\"memoryTotal\":%d,\"memoryUsedPercentage\":%.2f}}",
                pid,
                cpuUsage.get(),
                usedMemory.get(),
                maxMemory.get(),
                (usedMemory.get() * 100.0) / maxMemory.get()
        );
    }

    private static String extractQueryParam(String query, String paramName) {
        if (query == null || query.isEmpty()) {
            return null;
        }

        String[] params = query.split("&");
        for (String param : params) {
            String[] keyValue = param.split("=");
            if (keyValue.length == 2 && keyValue[0].equals(paramName)) {
                return keyValue[1];
            }
        }

        return null;
    }

    private static void sendErrorResponse(HttpExchange exchange, int statusCode, String message) throws IOException {
        String response = String.format("{\"error\":\"%s\"}", message);
        exchange.getResponseHeaders().set("Content-Type", "application/json");
        exchange.sendResponseHeaders(statusCode, response.length());
        try (OutputStream os = exchange.getResponseBody()) {
            os.write(response.getBytes());
        }
    }
}
