```java:SystemResourceMonitor.java
package com.monitor;

import java.io.IOException;
import java.lang.management.ManagementFactory;
import java.lang.management.MemoryMXBean;
import java.lang.management.OperatingSystemMXBean;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.StandardOpenOption;
import java.time.Duration;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

import com.sun.management.OperatingSystemMXBean as SunOperatingSystemMXBean;
import java.util.concurrent.atomic.AtomicReference;

public class SystemResourceMonitor {

    private static final String CONFIG_URL = "http://example.com/api/monitoring/config";
    private static final String LOG_FILE = "resource_alerts.json";
    private static final HttpClient httpClient = HttpClient.newBuilder()
            .version(HttpClient.Version.HTTP_2)
            .connectTimeout(Duration.ofSeconds(10))
            .build();

    private static final AtomicReference<MonitoringConfig> config = new AtomicReference<>(new MonitoringConfig(70.0, 80.0));

    public static void main(String[] args) {
        System.out.println("Starting System Resource Monitor...");

        // Schedule configuration sync
        scheduleConfigSync();

        // Start resource monitoring
        scheduleResourceMonitoring();
    }

    private static void scheduleConfigSync() {
        ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);
        scheduler.scheduleAtFixedRate(() -> {
            try {
                syncConfiguration();
            } catch (Exception e) {
                System.err.println("Failed to sync configuration: " + e.getMessage());
            }
        }, 0, 5, TimeUnit.MINUTES);
    }

    private static void scheduleResourceMonitoring() {
        ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);
        scheduler.scheduleAtFixedRate(() -> {
            try {
                checkResources();
            } catch (Exception e) {
                System.err.println("Error monitoring resources: " + e.getMessage());
            }
        }, 0, 30, TimeUnit.SECONDS);
    }

    private static void syncConfiguration() throws IOException, InterruptedException {
        System.out.println("Syncing configuration...");

        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(CONFIG_URL))
                .GET()
                .build();

        HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

        if (response.statusCode() == 200) {
            String body = response.body();
            // In real application, parse the JSON configuration
            // For this example, we're using dummy values
            config.set(new MonitoringConfig(70.0, 80.0));
            System.out.println("Configuration updated successfully");
        } else {
            System.out.println("Failed to fetch configuration: " + response.statusCode());
        }
    }

    private static void checkResources() throws IOException {
        OperatingSystemMXBean osBean = ManagementFactory.getOperatingSystemMXBean();
        MemoryMXBean memoryBean = ManagementFactory.getMemoryMXBean();

        double cpuLoad = 0.0;
        double memoryUsage = 0.0;

        // Get CPU usage
        if (osBean instanceof SunOperatingSystemMXBean) {
            cpuLoad = ((SunOperatingSystemMXBean) osBean).getCpuLoad() * 100;
        } else {
            cpuLoad = osBean.getSystemLoadAverage() * 100 / osBean.getAvailableProcessors();
        }

        // Get memory usage
        long usedMemory = memoryBean.getHeapMemoryUsage().getUsed() + memoryBean.getNonHeapMemoryUsage().getUsed();
        long maxMemory = Runtime.getRuntime().maxMemory();
        memoryUsage = ((double) usedMemory / maxMemory) * 100;

        // Check thresholds and log alerts
        MonitoringConfig currentConfig = config.get();

        if (cpuLoad > currentConfig.cpuThreshold()) {
            logAlert("CPU", cpuLoad);
        }

        if (memoryUsage > currentConfig.memoryThreshold()) {
            logAlert("Memory", memoryUsage);
        }
    }

    private static void logAlert(String resourceType, double utilization) throws IOException {
        LocalDateTime now = LocalDateTime.now();
        String timestamp = now.format(DateTimeFormatter.ISO_DATE_TIME);

        String alertJson = String.format("""
                {
                  "timestamp": "%s",
                  "resourceType": "%s",
                  "utilization": %.2f
                }
                """, timestamp, resourceType, utilization);

        Path logPath = Paths.get(LOG_FILE);
        Files.writeString(
                logPath, 
                alertJson + System.lineSeparator(), 
                StandardOpenOption.CREATE, 
                StandardOpenOption.APPEND
        );

        System.out.println("ALERT: High " + resourceType + " utilization: " + String.format("%.2f", utilization) + "%");
    }
}

record MonitoringConfig(double cpuThreshold, double memoryThreshold) {}
