I'll create a Rust CLI tool for monitoring system directories as requested:

```rust:src/main.rs
use chrono::Local;
use notify::{Config, Event, EventKind, RecommendedWatcher, RecursiveMode, Watcher};
use std::fs::{File, OpenOptions};
use std::io::Write;
use std::path::Path;
use std::sync::mpsc::{channel, Receiver};
use std::time::Duration;
use std::{env, fs, io, thread};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args: Vec<String> = env::args().collect();

    if args.len() < 2 {
        eprintln!("Usage: {} <directory_to_watch> [<directory_to_watch> ...]", args[0]);
        std::process::exit(1);
    }

    let (tx, rx) = channel();

    // Create watcher with custom configuration for performance
    let mut watcher = RecommendedWatcher::new(
        move |result| {
            if let Ok(event) = result {
                tx.send(event).unwrap();
            }
        },
        Config::default()
            .with_poll_interval(Duration::from_secs(1))
    )?;

    // Watch each directory provided as argument
    for dir in &args[1..] {
        let path = Path::new(dir);
        if !path.exists() {
            eprintln!("Directory does not exist: {}", dir);
            continue;
        }

        println!("Monitoring directory: {}", dir);
        watcher.watch(path, RecursiveMode::Recursive)?;
    }

    // Process events
    process_events(rx)?;

    Ok(())
}

fn process_events(rx: Receiver<Event>) -> Result<(), Box<dyn std::error::Error>> {
    let log_file_path = "system_logs.txt";

    // Create or open log file
    let mut log_file = OpenOptions::new()
        .create(true)
        .append(true)
        .open(log_file_path)?;

    // Write initial log entry
    let start_time = Local::now().format("%Y-%m-%d %H:%M:%S%.3f").to_string();
    writeln!(log_file, "[{}] File monitoring started", start_time)?;

    // Process events as they come in
    for event in rx {
        let timestamp = Local::now().format("%Y-%m-%d %H:%M:%S%.3f").to_string();
        let event_type = match event.kind {
            EventKind::Create(_) => "CREATED",
            EventKind::Modify(_) => "MODIFIED",
            EventKind::Remove(_) => "DELETED",
            _ => "OTHER",
        };

        for path in event.paths {
            let path_str = path.to_string_lossy();
            let log_entry = format!("[{}] {} {}", timestamp, event_type, path_str);

            println!("{}", log_entry);
            writeln!(log_file, "{}", log_entry)?;
            log_file.flush()?;
        }
    }

    Ok(())
}
