Here's a Java 11-based analytics engine for processing transactional data from a JSON REST API:

```java:TransactionAnalyticsEngine.java
package com.analytics;

import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.file.Path;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.Statement;
import java.time.Duration;
import java.util.List;
import java.util.Map;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.stream.Collectors;

import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;

public class TransactionAnalyticsEngine {
    private final HttpClient httpClient;
    private final ObjectMapper objectMapper;
    private final String dbUrl;
    private final ExecutorService executorService;

    public TransactionAnalyticsEngine(int threadPoolSize) {
        this.httpClient = HttpClient.newBuilder()
                .version(HttpClient.Version.HTTP_2)
                .connectTimeout(Duration.ofSeconds(10))
                .build();

        this.objectMapper = new ObjectMapper();
        this.dbUrl = "jdbc:sqlite:analytics.db";
        this.executorService = Executors.newFixedThreadPool(threadPoolSize);

        initializeDatabase();
    }

    private void initializeDatabase() {
        try (Connection conn = DriverManager.getConnection(dbUrl);
             Statement stmt = conn.createStatement()) {

            // Create transactions table
            stmt.execute("CREATE TABLE IF NOT EXISTS transactions (" +
                    "id TEXT PRIMARY KEY, " +
                    "amount REAL, " +
                    "timestamp TEXT, " +
                    "category TEXT, " +
                    "merchant TEXT)");

            // Create aggregation results table
            stmt.execute("CREATE TABLE IF NOT EXISTS aggregation_results (" +
                    "id INTEGER PRIMARY KEY AUTOINCREMENT, " +
                    "aggregation_type TEXT, " +
                    "category TEXT, " +
                    "value REAL, " +
                    "calculation_time TEXT)");

        } catch (Exception e) {
            throw new RuntimeException("Failed to initialize database", e);
        }
    }

    public CompletableFuture<List<Transaction>> fetchTransactionsAsync(String apiUrl) {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(apiUrl))
                .header("Accept", "application/json")
                .GET()
                .build();

        return httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
                .thenApplyAsync(response -> {
                    if (response.statusCode() != 200) {
                        throw new RuntimeException("API call failed with status: " + response.statusCode());
                    }
                    try {
                        return objectMapper.readValue(
                                response.body(), 
                                new TypeReference<List<Transaction>>() {});
                    } catch (Exception e) {
                        throw new RuntimeException("Failed to parse JSON response", e);
                    }
                }, executorService);
    }

    public CompletableFuture<Void> saveTransactionsAsync(List<Transaction> transactions) {
        return CompletableFuture.runAsync(() -> {
            String sql = "INSERT OR REPLACE INTO transactions (id, amount, timestamp, category, merchant) VALUES (?, ?, ?, ?, ?)";

            try (Connection conn = DriverManager.getConnection(dbUrl);
                 PreparedStatement pstmt = conn.prepareStatement(sql)) {

                conn.setAutoCommit(false);

                for (Transaction transaction : transactions) {
                    pstmt.setString(1, transaction.getId());
                    pstmt.setDouble(2, transaction.getAmount());
                    pstmt.setString(3, transaction.getTimestamp());
                    pstmt.setString(4, transaction.getCategory());
                    pstmt.setString(5, transaction.getMerchant());
                    pstmt.addBatch();
                }

                pstmt.executeBatch();
                conn.commit();

            } catch (Exception e) {
                throw new RuntimeException("Failed to save transactions", e);
            }
        }, executorService);
    }

    public CompletableFuture<Map<String, Double>> calculateSumByCategory() {
        return CompletableFuture.supplyAsync(() -> {
            String sql = "SELECT category, SUM(amount) as total FROM transactions GROUP BY category";
            return executeAggregationQuery(sql, "SUM");
        }, executorService);
    }

    public CompletableFuture<Map<String, Double>> calculateAverageByCategory() {
        return CompletableFuture.supplyAsync(() -> {
            String sql = "SELECT category, AVG(amount) as average FROM transactions GROUP BY category";
            return executeAggregationQuery(sql, "AVG");
        }, executorService);
    }

    public CompletableFuture<Map<String, Double>> calculateMaxByCategory() {
        return CompletableFuture.supplyAsync(() -> {
            String sql = "SELECT category, MAX(amount) as maximum FROM transactions GROUP BY category";
            return executeAggregationQuery(sql, "MAX");
        }, executorService);
    }

    private Map<String, Double> executeAggregationQuery(String sql, String aggregationType) {
        try (Connection conn = DriverManager.getConnection(dbUrl);
             Statement stmt = conn.createStatement();
             var resultSet = stmt.executeQuery(sql)) {

            Map<String, Double> results = new java.util.HashMap<>();

            while (resultSet.next()) {
                String category = resultSet.getString(1);
                double value = resultSet.getDouble(2);
                results.put(category, value);

                // Save aggregation result
                String insertSql = "INSERT INTO aggregation_results (aggregation_type, category, value, calculation_time) VALUES (?, ?, ?, datetime('now'))";
                try (PreparedStatement pstmt = conn.prepareStatement(insertSql)) {
                    pstmt.setString(1, aggregationType);
                    pstmt.setString(2, category);
                    pstmt.setDouble(3, value);
                    pstmt.executeUpdate();
                }
            }

            return results;

        } catch (Exception e) {
            throw new RuntimeException("Failed to execute aggregation query", e);
        }
    }

    public void shutdown() {
        executorService.shutdown();
    }

    // Main method for demonstration
    public static void main(String[] args) {
        TransactionAnalyticsEngine engine = new TransactionAnalyticsEngine(4);

        try {
            // Example API URL - replace with actual endpoint
            String apiUrl = "https://api.example.com/transactions";

            // Fetch and process transactions
            List<Transaction> transactions = engine.fetchTransactionsAsync(apiUrl).join();
            System.out.println("Fetched " + transactions.size() + " transactions");

            // Save transactions to database
            engine.saveTransactionsAsync(transactions).join();
            System.out.println("Saved transactions to database");

            // Perform aggregations
            Map<String, Double> sumByCategory = engine.calculateSumByCategory().join();
            Map<String, Double> avgByCategory = engine.calculateAverageByCategory().join();
            Map<String, Double> maxByCategory = engine.calculateMaxByCategory().join();

            // Print results
            System.out.println("Sum by category: " + sumByCategory);
            System.out.println("Average by category: " + avgByCategory);
            System.out.println("Max by category: " + maxByCategory);

        } catch (Exception e) {
            e.printStackTrace();
        } finally {
            engine.shutdown();
        }
    }
}
