Here's a Java application that monitors a directory for new images and performs OCR on them:

```java
import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.nio.file.*;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.logging.FileHandler;
import java.util.logging.Level;
import java.util.logging.Logger;
import java.util.logging.SimpleFormatter;

import net.sourceforge.tess4j.ITesseract;
import net.sourceforge.tess4j.Tesseract;
import net.sourceforge.tess4j.TesseractException;

public class ImageOCRMonitor {
    private static final Logger LOGGER = Logger.getLogger(ImageOCRMonitor.class.getName());
    private final Path directoryToWatch;
    private final ExecutorService executorService;
    private final ITesseract tesseract;

    public ImageOCRMonitor(String directoryPath) {
        this.directoryToWatch = Paths.get(directoryPath);
        this.executorService = Executors.newFixedThreadPool(Runtime.getRuntime().availableProcessors());
        this.tesseract = new Tesseract();

        // Initialize Tesseract - you'll need to specify your tessdata path
        tesseract.setDatapath("/usr/local/share/tessdata"); // Update this path as needed

        // Setup logging
        try {
            FileHandler fileHandler = new FileHandler("ocr_monitor.log", true);
            fileHandler.setFormatter(new SimpleFormatter());
            LOGGER.addHandler(fileHandler);
            LOGGER.setLevel(Level.INFO);
        } catch (IOException e) {
            System.err.println("Failed to initialize logger: " + e.getMessage());
        }
    }

    public void startMonitoring() {
        LOGGER.info("Starting directory monitoring for: " + directoryToWatch);

        try (WatchService watchService = FileSystems.getDefault().newWatchService()) {
            directoryToWatch.register(watchService, 
                    StandardWatchEventKinds.ENTRY_CREATE);

            LOGGER.info("Watch service registered for directory");

            while (true) {
                WatchKey key;
                try {
                    key = watchService.take(); // Wait for events
                } catch (InterruptedException e) {
                    LOGGER.severe("Watch service interrupted: " + e.getMessage());
                    Thread.currentThread().interrupt();
                    break;
                }

                for (WatchEvent<?> event : key.pollEvents()) {
                    WatchEvent.Kind<?> kind = event.kind();

                    if (kind == StandardWatchEventKinds.OVERFLOW) {
                        LOGGER.warning("Event overflow occurred");
                        continue;
                    }

                    @SuppressWarnings("unchecked")
                    WatchEvent<Path> pathEvent = (WatchEvent<Path>) event;
                    Path fileName = pathEvent.context();
                    Path fullPath = directoryToWatch.resolve(fileName);

                    LOGGER.info("Detected new file: " + fullPath);

                    if (isImageFile(fullPath.toString())) {
                        LOGGER.info("New image file detected: " + fullPath);
                        processImageFile(fullPath);
                    }
                }

                boolean valid = key.reset();
                if (!valid) {
                    LOGGER.severe("Directory is no longer accessible. Exiting monitor.");
                    break;
                }
            }

        } catch (IOException e) {
            LOGGER.severe("Error setting up directory watcher: " + e.getMessage());
        } finally {
            executorService.shutdown();
        }
    }

    private boolean isImageFile(String filePath) {
        String lowercasePath = filePath.toLowerCase();
        return lowercasePath.endsWith(".jpg") || lowercasePath.endsWith(".jpeg") || 
               lowercasePath.endsWith(".png") || lowercasePath.endsWith(".bmp") || 
               lowercasePath.endsWith(".tiff") || lowercasePath.endsWith(".gif");
    }

    private void processImageFile(Path imagePath) {
        executorService.submit(() -> {
            String imageFilePath = imagePath.toString();
            String baseFileName = imagePath.getFileName().toString();
            String textFilePath = imageFilePath.substring(0, imageFilePath.lastIndexOf('.')) + ".txt";

            LOGGER.info("Processing image file: " + imageFilePath);

            try {
                File imageFile = new File(imageFilePath);
                String result = tesseract.doOCR(imageFile);

                LOGGER.info("OCR completed for: " + imageFilePath);

                // Save the extracted text to a file
                try (FileWriter writer = new FileWriter(textFilePath)) {
                    writer.write(result);
                    LOGGER.info("OCR text saved to: " + textFilePath);
                } catch (IOException e) {
                    LOGGER.severe("Failed to save OCR text: " + e.getMessage());
                }

            } catch (TesseractException e) {
                LOGGER.severe("OCR processing failed for " + imageFilePath + ": " + e.getMessage());
            }
        });
    }

    public static void main(String[] args) {
        if (args.length < 1) {
            System.out.println("Please provide a directory path to monitor");
            return;
        }

        String directoryPath = args[0];
        File directory = new File(directoryPath);

        if (!directory.exists() || !directory.isDirectory()) {
            System.out.println("The specified path is not a valid directory");
            return;
        }

        ImageOCRMonitor monitor = new ImageOCRMonitor(directoryPath);
        monitor.startMonitoring();
    }
}
