package stockmarket;

import java.io.IOException;
import java.math.BigDecimal;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.Random;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

public class StockMarketSimulation {
    private final ConcurrentHashMap<String, Stock> stocks = new ConcurrentHashMap<>();
    private final ExecutorService transactionExecutor = Executors.newFixedThreadPool(10);
    private final ScheduledExecutorService marketScheduler = Executors.newScheduledThreadPool(2);
    private final MessageService messageService = new MessageService();
    private MarketState currentMarketState = MarketState.STABLE;
    private final Random random = new Random();

    public static void main(String[] args) {
        StockMarketSimulation simulation = new StockMarketSimulation();
        simulation.initialize();
        simulation.startSimulation();
    }

    private void initialize() {
        // Create stocks of different types
        stocks.put("AAPL", new TechnologyStock("AAPL", new BigDecimal("180.50"), 1000000));
        stocks.put("MSFT", new TechnologyStock("MSFT", new BigDecimal("330.75"), 800000));
        stocks.put("JPM", new FinancialStock("JPM", new BigDecimal("145.25"), 600000));
        stocks.put("XOM", new EnergyStock("XOM", new BigDecimal("105.60"), 750000));
        stocks.put("PG", new ConsumerStock("PG", new BigDecimal("160.30"), 500000));

        System.out.println("Stock market simulation initialized with " + stocks.size() + " stocks.");
    }

    private void startSimulation() {
        // Schedule market state changes
        marketScheduler.scheduleAtFixedRate(this::changeMarketState, 10, 30, TimeUnit.SECONDS);

        // Schedule continuous stock price updates
        marketScheduler.scheduleAtFixedRate(this::updateStockPrices, 1, 2, TimeUnit.SECONDS);

        // Start processing random transactions
        for (int i = 0; i < 5; i++) {
            transactionExecutor.submit(this::processRandomTransactions);
        }

        System.out.println("Stock market simulation started.");
    }

    private void changeMarketState() {
        // Randomly change market state
        int stateIndex = random.nextInt(MarketState.values().length);
        MarketState newState = MarketState.values()[stateIndex];

        if (newState != currentMarketState) {
            MarketState oldState = currentMarketState;
            currentMarketState = newState;

            MarketStateChange stateChange = new MarketStateChange(
                    oldState, 
                    newState, 
                    LocalDateTime.now());

            System.out.println("Market state changed: " + stateChange);
            messageService.sendMarketUpdate("MARKET_STATE_CHANGE", 
                    "Market changed from " + oldState + " to " + newState);
        }
    }

    private void updateStockPrices() {
        stocks.forEach((symbol, stock) -> {
            try {
                BigDecimal priceChange = calculatePriceChange(stock);
                Stock updatedStock = stock.updatePrice(priceChange);
                stocks.put(symbol, updatedStock);

                if (priceChange.abs().compareTo(new BigDecimal("1.0")) >= 0) {
                    StockPriceUpdate update = new StockPriceUpdate(
                            updatedStock.symbol(), 
                            stock.price(), 
                            updatedStock.price(), 
                            LocalDateTime.now());
                    System.out.println(update);
                }
            } catch (Exception e) {
                System.err.println("Error updating price for " + symbol + ": " + e.getMessage());
            }
        });
    }

    private BigDecimal calculatePriceChange(Stock stock) {
        // Base volatility based on stock type
        double baseVolatility = switch (stock) {
            case TechnologyStock t -> 0.025;
            case FinancialStock f -> 0.015;
            case EnergyStock e -> 0.020;
            case ConsumerStock c -> 0.010;
        };

        // Adjust based on market state
        double marketMultiplier = switch (currentMarketState) {
            case BULL -> 1.5;
            case BEAR -> 0.5;
            case CRASH -> -3.0;
            case STABLE -> 1.0;
            case VOLATILE -> random.nextDouble() * 3;
        };

        // Calculate random change with current factors
        double changePercent = baseVolatility * marketMultiplier * (random.nextDouble() * 2 - 1);
        BigDecimal currentPrice = stock.price();
        return currentPrice.multiply(new BigDecimal(changePercent));
    }

    private void processRandomTransactions() {
        while (!Thread.currentThread().isInterrupted()) {
            try {
                // Create and process a random transaction
                String symbol = getRandomStockSymbol();
                if (symbol != null) {
                    int quantity = 10 + random.nextInt(990); // 10-1000 shares
                    boolean isBuy = random.nextBoolean();

                    Transaction transaction = new Transaction(
                            symbol,
                            isBuy ? TransactionType.BUY : TransactionType.SELL,
                            quantity,
                            LocalDateTime.now()
                    );

                    processTransaction(transaction);
                }

                // Sleep for a random period before next transaction
                Thread.sleep(500 + random.nextInt(2000));
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                break;
            } catch (Exception e) {
                System.err.println("Error processing transaction: " + e.getMessage());
            }
        }
    }

    private void processTransaction(Transaction transaction) {
        System.out.println("Processing: " + transaction);

        Stock stock = stocks.get(transaction.symbol());
        if (stock == null) return;

        // Update volume
        int volumeChange = transaction.type() == TransactionType.BUY 
                          ? transaction.quantity() : -transaction.quantity();

        Stock updatedStock = stock.updateVolume(volumeChange);
        stocks.put(transaction.symbol(), updatedStock);

        // Simulate price impact based on transaction
        double priceImpact = 0.0001 * transaction.quantity() 
                          * (transaction.type() == TransactionType.BUY ? 1 : -1);

        BigDecimal priceChange = stock.price().multiply(new BigDecimal(priceImpact));
        Stock finalStock = updatedStock.updatePrice(priceChange);
        stocks.put(transaction.symbol(), finalStock);

        // Notify large transactions
        if (transaction.quantity() > 500) {
            messageService.sendMarketUpdate(
                "LARGE_TRANSACTION", 
                "Large " + transaction.type() + " of " + transaction.quantity() + 
                " shares of " + transaction.symbol()
            );
        }
    }

    private String getRandomStockSymbol() {
        if (stocks.isEmpty()) return null;

        List<String> symbols = new ArrayList<>(stocks.keySet());
        return symbols.get(random.nextInt(symbols.size()));
    }

    // Shutdown method
    public void shutdown() {
        transactionExecutor.shutdown();
        marketScheduler.shutdown();
        System.out.println("Stock market simulation shutdown initiated.");
    }
}
