package stockmarket;

import java.math.BigDecimal;
import java.math.RoundingMode;

// Sealed class hierarchy for stock types
public sealed abstract class Stock 
    permits TechnologyStock, FinancialStock, EnergyStock, ConsumerStock {

    private final String symbol;
    private final BigDecimal price;
    private final int volume;

    protected Stock(String symbol, BigDecimal price, int volume) {
        this.symbol = symbol;
        this.price = price.setScale(2, RoundingMode.HALF_UP);
        this.volume = volume;
    }

    public String symbol() {
        return symbol;
    }

    public BigDecimal price() {
        return price;
    }

    public int volume() {
        return volume;
    }

    public abstract Stock updatePrice(BigDecimal priceChange);

    public abstract Stock updateVolume(int volumeChange);
}

// Concrete stock types using records for implementation
final class TechnologyStock extends Stock {
    public TechnologyStock(String symbol, BigDecimal price, int volume) {
        super(symbol, price, volume);
    }

    @Override
    public Stock updatePrice(BigDecimal priceChange) {
        BigDecimal newPrice = price().add(priceChange).max(BigDecimal.ONE);
        return new TechnologyStock(symbol(), newPrice, volume());
    }

    @Override
    public Stock updateVolume(int volumeChange) {
        int newVolume = Math.max(0, volume() + volumeChange);
        return new TechnologyStock(symbol(), price(), newVolume);
    }
}

