package stockmarket;

import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.concurrent.CompletableFuture;

public class MessageService {
    private final HttpClient httpClient;
    private static final String DEFAULT_NOTIFICATION_ENDPOINT = "http://localhost:8080/market-updates";
    private final String notificationEndpoint;

    public MessageService() {
        this(DEFAULT_NOTIFICATION_ENDPOINT);
    }

    public MessageService(String notificationEndpoint) {
        this.notificationEndpoint = notificationEndpoint;
        this.httpClient = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(5))
                .build();
    }

    public void sendMarketUpdate(String eventType, String message) {
        try {
            String payload = """
                {
                    "eventType": "%s",
                    "message": "%s",
                    "timestamp": "%s"
                }
                """.formatted(eventType, message, java.time.LocalDateTime.now());

            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(notificationEndpoint))
                    .header("Content-Type", "application/json")
                    .POST(HttpRequest.BodyPublishers.ofString(payload))
                    .timeout(Duration.ofSeconds(10))
                    .build();

            // Asynchronous notification - we don't need to wait for the response
            CompletableFuture<HttpResponse<String>> future = httpClient.sendAsync(
                    request, HttpResponse.BodyHandlers.ofString());

            future.thenAccept(response -> {
                if (response.statusCode() >= 200 && response.statusCode() < 300) {
                    System.out.println("Market update sent successfully: " + eventType);
                } else {
                    System.err.println("Failed to send market update: " + response.statusCode());
                }
            }).exceptionally(ex -> {
                System.err.println("Error sending market update: " + ex.getMessage());
                return null;
            });

        } catch (Exception e) {
            System.err.println("Error creating market update request: " + e.getMessage());
        }
    }
}
