                try {
                    double amount = Double.parseDouble(amountStr);
                    double convertedAmount = exchangeRateService.convert(amount, fromCurrency, toCurrency);

                    String response = String.format(
                        "{\"from\": \"%s\", \"to\": \"%s\", \"amount\": %.2f, \"convertedAmount\": %.2f}",
                        fromCurrency, toCurrency, amount, convertedAmount
                    );

                    sendResponse(exchange, 200, response);
                } catch (NumberFormatException e) {
                    sendResponse(exchange, 400, "{\"error\": \"Invalid amount format\"}");
                } catch (Exception e) {
                    sendResponse(exchange, 500, "{\"error\": \"" + e.getMessage() + "\"}");
                }
            } else {
                exchange.sendResponseHeaders(405, 0);
                exchange.getResponseBody().close();
            }
        }

        private Map<String, String> parseQueryParams(URI uri) {
            Map<String, String> params = new HashMap<>();
            String query = uri.getQuery();
            if (query != null) {
                String[] pairs = query.split("&");
                for (String pair : pairs) {
                    int idx = pair.indexOf("=");
                    if (idx > 0) {
                        String key = URLDecoder.decode(pair.substring(0, idx), StandardCharsets.UTF_8);
                        String value = URLDecoder.decode(pair.substring(idx + 1), StandardCharsets.UTF_8);
                        params.put(key, value);
                    }
                }
            }
            return params;
        }

        private void sendResponse(HttpExchange exchange, int statusCode, String response) throws IOException {
            exchange.getResponseHeaders().set("Content-Type", "application/json");
            exchange.sendResponseHeaders(statusCode, response.getBytes().length);
            try (OutputStream os = exchange.getResponseBody()) {
                os.write(response.getBytes());
            }
        }
    }
}
