package com.currencyconverter;

import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.time.Instant;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class ExchangeRateService {
    private static final String EXCHANGE_RATE_API_URL = "https://open.er-api.com/v6/latest/";
    private static final long CACHE_EXPIRATION_MINUTES = 10;

    private final HttpClient httpClient;
    private final Map<String, CachedRates> rateCache;

    public ExchangeRateService() {
        this.httpClient = HttpClient.newBuilder()
                .version(HttpClient.Version.HTTP_2)
                .connectTimeout(Duration.ofSeconds(10))
                .build();
        this.rateCache = new ConcurrentHashMap<>();
    }

    public double convert(double amount, String fromCurrency, String toCurrency) throws IOException, InterruptedException {
        fromCurrency = fromCurrency.toUpperCase();
        toCurrency = toCurrency.toUpperCase();

        if (fromCurrency.equals(toCurrency)) {
            return amount;
        }

        Map<String, Double> rates = getRatesForCurrency(fromCurrency);

        if (!rates.containsKey(toCurrency)) {
            throw new IllegalArgumentException("Unsupported currency: " + toCurrency);
        }

        return amount * rates.get(toCurrency);
    }

    private Map<String, Double> getRatesForCurrency(String baseCurrency) throws IOException, InterruptedException {
        // Check if we have a valid cached entry
        CachedRates cachedRates = rateCache.get(baseCurrency);
        if (cachedRates != null && !cachedRates.isExpired()) {
            return cachedRates.getRates();
        }

        // Fetch fresh rates
        HttpRequest request = HttpRequest.newBuilder()
                .GET()
                .uri(URI.create(EXCHANGE_RATE_API_URL + baseCurrency))
                .build();

        HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

        if (response.statusCode() != 200) {
            throw new IOException("Failed to fetch exchange rates: HTTP " + response.statusCode());
        }

        Map<String, Double> rates = parseRatesFromResponse(response.body());

        // Cache the result
        rateCache.put(baseCurrency, new CachedRates(rates));

        return rates;
    }

    private Map<String, Double> parseRatesFromResponse(String responseBody) {
        Map<String, Double> rates = new ConcurrentHashMap<>();

        // Simple regex-based JSON parsing to avoid external dependencies
        Pattern ratesPattern = Pattern.compile("\"rates\":\\{([^}]+)\\}");
        Matcher ratesMatcher = ratesPattern.matcher(responseBody);

        if (ratesMatcher.find()) {
            String ratesJson = ratesMatcher.group(1);
            Pattern entryPattern = Pattern.compile("\"([A-Z]{3})\":([0-9.]+)");
            Matcher entryMatcher = entryPattern.matcher(ratesJson);

            while (entryMatcher.find()) {
                String currency = entryMatcher.group(1);
                double rate = Double.parseDouble(entryMatcher.group(2));
                rates.put(currency, rate);
            }
        }

        return rates;
    }

    private static class CachedRates {
        private final Map<String, Double> rates;
        private final Instant timestamp;

        public CachedRates(Map<String, Double> rates) {
            this.rates = rates;
            this.timestamp = Instant.now();
        }

        public Map<String, Double> getRates() {
            return rates;
        }

        public boolean isExpired() {
            return Instant.now().isAfter(timestamp.plus(Duration.ofMinutes(CACHE_EXPIRATION_MINUTES)));
        }
    }
}
