package com.serverhealth;

import com.sun.net.httpserver.HttpExchange;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpServer;
import java.io.IOException;
import java.io.OutputStream;
import java.lang.management.ManagementFactory;
import java.lang.management.MemoryMXBean;
import java.lang.management.OperatingSystemMXBean;
import java.net.InetSocketAddress;
import java.nio.charset.StandardCharsets;
import java.nio.file.FileStore;
import java.nio.file.FileSystems;
import java.nio.file.Files;
import java.time.LocalDateTime;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicReference;

public class ServerHealthMonitor {

    private static final int SERVER_PORT = 8080;
    private static final String HEALTH_ENDPOINT = "/health";
    private static final long DATA_EXPIRY_MINUTES = 1;

    // Thread-safe cache for storing the latest server health data
    private final AtomicReference<ServerHealthData> healthDataCache = new AtomicReference<>(new ServerHealthData());
    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);

    public static void main(String[] args) throws IOException {
        ServerHealthMonitor monitor = new ServerHealthMonitor();
        monitor.startMonitoring();
        monitor.startHttpServer();
    }

    public void startMonitoring() {
        // Schedule the monitoring task to run every minute
        scheduler.scheduleAtFixedRate(this::collectHealthData, 0, DATA_EXPIRY_MINUTES, TimeUnit.MINUTES);
    }

    private void collectHealthData() {
        try {
            // Get system metrics
            OperatingSystemMXBean osBean = ManagementFactory.getOperatingSystemMXBean();
            MemoryMXBean memoryBean = ManagementFactory.getMemoryMXBean();

            double cpuLoad = osBean.getSystemLoadAverage();
            long totalMemory = memoryBean.getHeapMemoryUsage().getMax();
            long usedMemory = memoryBean.getHeapMemoryUsage().getUsed();
            double memoryUsage = (double) usedMemory / totalMemory * 100.0;

            // Collect disk usage information
            ConcurrentHashMap<String, Double> diskUsage = new ConcurrentHashMap<>();
            for (FileStore store : FileSystems.getDefault().getFileStores()) {
                long totalSpace = store.getTotalSpace();
                long usableSpace = store.getUsableSpace();
                double usagePercentage = (double) (totalSpace - usableSpace) / totalSpace * 100.0;
                diskUsage.put(store.name(), usagePercentage);
            }

            // Update the health data cache with new values
            ServerHealthData newData = new ServerHealthData();
            newData.setTimestamp(LocalDateTime.now());
            newData.setCpuLoad(cpuLoad);
            newData.setMemoryUsage(memoryUsage);
            newData.setDiskUsage(diskUsage);

            healthDataCache.set(newData);

        } catch (Exception e) {
            System.err.println("Error collecting health data: " + e.getMessage());
        }
    }

    private void startHttpServer() throws IOException {
        HttpServer server = HttpServer.create(new InetSocketAddress(SERVER_PORT), 0);
        server.createContext(HEALTH_ENDPOINT, new HealthHandler());
        server.setExecutor(null); // Use the default executor
        server.start();
        System.out.println("Server started on port " + SERVER_PORT);
    }

    private class HealthHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if ("GET".equals(exchange.getRequestMethod())) {
                ServerHealthData healthData = healthDataCache.get();
                String response = healthData.toJson();

                exchange.getResponseHeaders().set("Content-Type", "application/json");
                exchange.sendResponseHeaders(200, response.getBytes(StandardCharsets.UTF_8).length);

                try (OutputStream os = exchange.getResponseBody()) {
                    os.write(response.getBytes(StandardCharsets.UTF_8));
                }
            } else {
                exchange.sendResponseHeaders(405, -1); // Method Not Allowed
            }
        }
    }

    // Inner class representing server health data
    private static class ServerHealthData {
        private LocalDateTime timestamp;
        private double cpuLoad;
        private double memoryUsage;
        private ConcurrentHashMap<String, Double> diskUsage = new ConcurrentHashMap<>();

        public void setTimestamp(LocalDateTime timestamp) {
            this.timestamp = timestamp;
        }

        public void setCpuLoad(double cpuLoad) {
            this.cpuLoad = cpuLoad;
        }

        public void setMemoryUsage(double memoryUsage) {
            this.memoryUsage = memoryUsage;
        }

        public void setDiskUsage(ConcurrentHashMap<String, Double> diskUsage) {
            this.diskUsage = diskUsage;
        }

        public String toJson() {
            StringBuilder json = new StringBuilder();
            json.append("{\n");
            json.append("  \"timestamp\": \"").append(timestamp).append("\",\n");
            json.append("  \"cpuLoad\": ").append(cpuLoad).append(",\n");
            json.append("  \"memoryUsage\": ").append(memoryUsage).append(",\n");
            json.append("  \"diskUsage\": {\n");

            int count = 0;
            for (var entry : diskUsage.entrySet()) {
                json.append("    \"").append(entry.getKey()).append("\": ").append(entry.getValue());
                if (count < diskUsage.size() - 1) {
                    json.append(",");
                }
                json.append("\n");
                count++;
            }

            json.append("  }\n");
            json.append("}");

            return json.toString();
        }
    }
}
