package com.urlshortener;

import java.net.URI;
import java.net.http.HttpClient;
import java.security.SecureRandom;
import java.time.Duration;
import java.util.Base64;
import java.util.Map;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;

public class UrlShortenerService {
    private final Map<String, UrlEntry> urlMappings = new ConcurrentHashMap<>();
    private final HttpClient httpClient;
    private final SecureRandom random = new SecureRandom();
    private final String apiKey = generateApiKey(); // In production, should be loaded from secure storage

    public UrlShortenerService() {
        this.httpClient = HttpClient.newBuilder()
                .version(HttpClient.Version.HTTP_2)
                .followRedirects(HttpClient.Redirect.NORMAL)
                .connectTimeout(Duration.ofSeconds(10))
                .build();
    }

    public String getApiKey() {
        return apiKey;
    }

    private String generateApiKey() {
        byte[] bytes = new byte[32];
        random.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    public CompletableFuture<Boolean> validateUrl(String url) {
        return CompletableFuture.supplyAsync(() -> {
            try {
                URI uri = URI.create(url);
                // Simple validation, can be expanded as needed
                return uri.getScheme() != null && 
                       (uri.getScheme().equals("http") || uri.getScheme().equals("https"));
            } catch (Exception e) {
                return false;
            }
        });
    }

    public CompletableFuture<String> createShortUrl(String longUrl) {
        return validateUrl(longUrl)
                .thenApply(valid -> {
                    if (!valid) {
                        throw new IllegalArgumentException("Invalid URL format");
                    }

                    String alias = generateUniqueAlias();
                    urlMappings.put(alias, new UrlEntry(longUrl));
                    return alias;
                });
    }

    public UrlEntry getOriginalUrl(String alias) {
        UrlEntry entry = urlMappings.get(alias);
        if (entry != null) {
            entry.incrementAccessCount();
            return entry;
        }
        return null;
    }

    public Map<String, UrlEntry> getAllUrls() {
        return urlMappings;
    }

    private String generateUniqueAlias() {
        // Generate a short, unique identifier
        byte[] bytes = new byte[4];
        String alias;
        do {
            random.nextBytes(bytes);
            alias = Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
        } while (urlMappings.containsKey(alias));

        return alias;
    }

    public static class UrlEntry {
        private final String originalUrl;
        private long accessCount;
        private final long creationTime;

        public UrlEntry(String originalUrl) {
            this.originalUrl = originalUrl;
            this.accessCount = 0;
            this.creationTime = System.currentTimeMillis();
        }

        public String getOriginalUrl() {
            return originalUrl;
        }

        public long getAccessCount() {
            return accessCount;
        }

        public long getCreationTime() {
            return creationTime;
        }

        public synchronized void incrementAccessCount() {
            accessCount++;
        }
    }
}
