package com.urlshortener;

import com.sun.net.httpserver.HttpExchange;
import com.sun.net.httpserver.HttpHandler;
import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.util.concurrent.CompletableFuture;
import java.util.stream.Collectors;

public class ShortenUrlHandler implements HttpHandler {
    private final UrlShortenerService service;

    public ShortenUrlHandler(UrlShortenerService service) {
        this.service = service;
    }

    @Override
    public void handle(HttpExchange exchange) throws IOException {
        if (!exchange.getRequestMethod().equals("POST")) {
            sendResponse(exchange, 405, "Method Not Allowed");
            return;
        }

        // Validate API key for security
        String authHeader = exchange.getRequestHeaders().getFirst("Authorization");
        if (authHeader == null || !authHeader.equals("Bearer " + service.getApiKey())) {
            sendResponse(exchange, 401, "Unauthorized");
            return;
        }

        // Read request body
        try (BufferedReader br = new BufferedReader(new InputStreamReader(exchange.getRequestBody()))) {
            String requestBody = br.lines().collect(Collectors.joining());

            // Very simple parsing - in a real app use a proper JSON parser
            if (requestBody.contains("url=")) {
                String longUrl = requestBody.substring(requestBody.indexOf("url=") + 4);

                CompletableFuture<String> futureAlias = service.createShortUrl(longUrl);

                futureAlias.thenAccept(alias -> {
                    String baseUrl = "http://" + exchange.getRequestHeaders().getFirst("Host") + "/";
                    String shortUrl = baseUrl + alias;
                    String response = "{\"shortUrl\":\"" + shortUrl + "\",\"alias\":\"" + alias + "\"}";
                    try {
                        sendResponse(exchange, 200, response);
                    } catch (IOException e) {
                        e.printStackTrace();
                    }
                }).exceptionally(ex -> {
                    try {
                        sendResponse(exchange, 400, "{\"error\":\"" + ex.getMessage() + "\"}");
                    } catch (IOException e) {
                        e.printStackTrace();
                    }
                    return null;
                });
            } else {
                sendResponse(exchange, 400, "{\"error\":\"Missing url parameter\"}");
            }
        }
    }

    private void sendResponse(HttpExchange exchange, int statusCode, String response) throws IOException {
        exchange.getResponseHeaders().set("Content-Type", "application/json");
        exchange.sendResponseHeaders(statusCode, response.getBytes().length);
        try (OutputStream os = exchange.getResponseBody()) {
            os.write(response.getBytes());
        }
    }
}
