package com.urlshortener;

import com.sun.net.httpserver.HttpExchange;
import com.sun.net.httpserver.HttpHandler;
import java.io.IOException;
import java.io.OutputStream;

public class RedirectHandler implements HttpHandler {
    private final UrlShortenerService service;

    public RedirectHandler(UrlShortenerService service) {
        this.service = service;
    }

    @Override
    public void handle(HttpExchange exchange) throws IOException {
        String path = exchange.getRequestURI().getPath();
        if (path.equals("/")) {
            // Root path - could serve a simple form here
            String response = "<html><body><h1>URL Shortener</h1></body></html>";
            exchange.getResponseHeaders().set("Content-Type", "text/html");
            exchange.sendResponseHeaders(200, response.getBytes().length);
            try (OutputStream os = exchange.getResponseBody()) {
                os.write(response.getBytes());
            }
            return;
        }

        // Extract alias from path
        String alias = path.substring(1);
        UrlShortenerService.UrlEntry entry = service.getOriginalUrl(alias);

        if (entry != null) {
            // Redirect to the original URL
            exchange.getResponseHeaders().set("Location", entry.getOriginalUrl());
            exchange.sendResponseHeaders(302, -1);
        } else {
            // Alias not found
            String response = "<html><body><h1>404 Not Found</h1><p>Short URL not found.</p></body></html>";
            exchange.getResponseHeaders().set("Content-Type", "text/html");
            exchange.sendResponseHeaders(404, response.getBytes().length);
            try (OutputStream os = exchange.getResponseBody()) {
                os.write(response.getBytes());
            }
        }
    }
}
