package com.urlshortener;

import com.sun.net.httpserver.HttpExchange;
import com.sun.net.httpserver.HttpHandler;
import java.io.IOException;
import java.io.OutputStream;
import java.util.Map;

public class StatsHandler implements HttpHandler {
    private final UrlShortenerService service;

    public StatsHandler(UrlShortenerService service) {
        this.service = service;
    }

    @Override
    public void handle(HttpExchange exchange) throws IOException {
        if (!exchange.getRequestMethod().equals("GET")) {
            sendResponse(exchange, 405, "Method Not Allowed");
            return;
        }

        // Validate API key for security
        String authHeader = exchange.getRequestHeaders().getFirst("Authorization");
        if (authHeader == null || !authHeader.equals("Bearer " + service.getApiKey())) {
            sendResponse(exchange, 401, "Unauthorized");
            return;
        }

        // Build JSON statistics report
        StringBuilder stats = new StringBuilder();
        stats.append("{\"urls\":[");

        Map<String, UrlShortenerService.UrlEntry> allUrls = service.getAllUrls();
        boolean first = true;

        for (Map.Entry<String, UrlShortenerService.UrlEntry> entry : allUrls.entrySet()) {
            if (!first) {
                stats.append(",");
            } else {
                first = false;
            }

            stats.append("{")
                .append("\"alias\":\"").append(entry.getKey()).append("\",")
                .append("\"originalUrl\":\"").append(entry.getValue().getOriginalUrl()).append("\",")
                .append("\"accessCount\":").append(entry.getValue().getAccessCount()).append(",")
                .append("\"creationTime\":").append(entry.getValue().getCreationTime())
                .append("}");
        }

        stats.append("]}");

        exchange.getResponseHeaders().set("Content-Type", "application/json");
        exchange.sendResponseHeaders(200, stats.toString().getBytes().length);
        try (OutputStream os = exchange.getResponseBody()) {
            os.write(stats.toString().getBytes());
        }
    }

    private void sendResponse(HttpExchange exchange, int statusCode, String response) throws IOException {
        exchange.getResponseHeaders().set("Content-Type", "text/plain");
        exchange.sendResponseHeaders(statusCode, response.getBytes().length);
        try (OutputStream os = exchange.getResponseBody()) {
            os.write(response.getBytes());
        }
    }
}
