```rust
use std::path::Path;
use std::error::Error;
use hashbrown::HashMap;
use tokio::fs;
use reqwest;
use serde_json;
use sha2::{Sha256, Digest};
use clap::Parser;

#[derive(Parser)]
#[command(version, about = "Asynchronously fetch URLs and save responses")]
struct Args {
    /// Path to JSON file containing URLs
    #[arg(short, long)]
    input: String,

    /// Directory to save responses
    #[arg(short, long, default_value = "output")]
    output_dir: String,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    let args = Args::parse();

    // Create output directory if it doesn't exist
    fs::create_dir_all(&args.output_dir).await?;

    // Read and parse the JSON file
    let json_content = fs::read_to_string(&args.input).await?;
    let urls: Vec<String> = serde_json::from_str(&json_content)?;

    // Create a client for reuse across requests
    let client = reqwest::Client::new();

    // Create a collection to track tasks
    let mut tasks = Vec::new();

    // Start a task for each URL
    for url in urls {
        let client = client.clone();
        let output_dir = args.output_dir.clone();

        let task = tokio::spawn(async move {
            match fetch_and_save(&client, &url, &output_dir).await {
                Ok(_) => println!("Successfully processed: {}", url),
                Err(e) => eprintln!("Error processing {}: {}", url, e),
            }
        });

        tasks.push(task);
    }

    // Wait for all tasks to complete
    for task in tasks {
        task.await?;
    }

    println!("All URLs processed");
    Ok(())
}

async fn fetch_and_save(
    client: &reqwest::Client, 
    url: &str, 
    output_dir: &str
) -> Result<(), Box<dyn Error>> {
    // Generate hash for the URL
    let mut hasher = Sha256::new();
    hasher.update(url.as_bytes());
    let hash = format!("{:x}", hasher.finalize());

    // Fetch the URL
    let response = client.get(url).send().await?;
    let content = response.bytes().await?;

    // Create the output file path
    let file_path = Path::new(output_dir).join(format!("{}.bin", hash));

    // Write the response to a file
    fs::write(file_path, content).await?;

    Ok(())
}
