import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.time.Duration;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class HttpsAnalyticsDaemon {
    private static final Pattern IP_PATTERN = Pattern.compile("\\b(?:\\d{1,3}\\.){3}\\d{1,3}\\b");
    private final Map<String, Integer> ipThreatScores = new ConcurrentHashMap<>();
    private final HttpClient httpClient;
    private final String blacklistServiceUrl;
    private final Path logFilePath;
    private long lastPosition = 0;

    public HttpsAnalyticsDaemon(String logFilePath, String blacklistServiceUrl) {
        this.logFilePath = Paths.get(logFilePath);
        this.blacklistServiceUrl = blacklistServiceUrl;
        this.httpClient = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(10))
                .build();
    }

    public void start() {
        try {
            while (true) {
                processLogUpdates();
                Thread.sleep(1000); // Check for updates every second
            }
        } catch (InterruptedException | IOException e) {
            System.err.println("Error in processing: " + e.getMessage());
            e.printStackTrace();
        }
    }

    private void processLogUpdates() throws IOException {
        long fileSize = Files.size(logFilePath);

        if (fileSize > lastPosition) {
            try {
                String newContent = readFileFromPosition(lastPosition);
                processContent(newContent);
                lastPosition = fileSize;
            } catch (IOException e) {
                System.err.println("Error reading log file: " + e.getMessage());
                throw e;
            }
        }
    }

    private String readFileFromPosition(long position) throws IOException {
        byte[] bytes = Files.readAllBytes(logFilePath);
        return new String(bytes, (int) position, (int) (bytes.length - position));
    }

    private void processContent(String content) {
        Matcher matcher = IP_PATTERN.matcher(content);
        while (matcher.find()) {
            String ipAddress = matcher.group();
            checkBlacklist(ipAddress);
        }
    }

    private void checkBlacklist(String ipAddress) {
        try {
            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(blacklistServiceUrl + "/check?ip=" + ipAddress))
                    .GET()
                    .timeout(Duration.ofSeconds(5))
                    .build();

            httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
                    .thenApply(HttpResponse::body)
                    .thenAccept(response -> {
                        if (response.contains("blacklisted")) {
                            incrementThreatScore(ipAddress);
                            System.out.println("Blacklisted IP detected: " + ipAddress + 
                                    " - Current threat score: " + ipThreatScores.get(ipAddress));
                        }
                    })
                    .exceptionally(e -> {
                        System.err.println("Error checking blacklist for IP " + ipAddress + ": " + e.getMessage());
                        return null;
                    });
        } catch (Exception e) {
            System.err.println("Failed to check blacklist for IP " + ipAddress + ": " + e.getMessage());
        }
    }

    private void incrementThreatScore(String ipAddress) {
        ipThreatScores.compute(ipAddress, (ip, score) -> (score == null) ? 1 : score + 1);
    }

    public void displayThreatScores() {
        System.out.println("Current IP Threat Scores:");
        ipThreatScores.forEach((ip, score) -> 
            System.out.println(ip + ": " + score)
        );
    }

    public static void main(String[] args) {
        if (args.length < 2) {
            System.out.println("Usage: java HttpsAnalyticsDaemon <log_file_path> <blacklist_service_url>");
            System.exit(1);
        }

        String logFilePath = args[0];
        String blacklistServiceUrl = args[1];

        HttpsAnalyticsDaemon daemon = new HttpsAnalyticsDaemon(logFilePath, blacklistServiceUrl);

        // Add shutdown hook to display results before exiting
        Runtime.getRuntime().addShutdownHook(new Thread(daemon::displayThreatScores));

        System.out.println("Starting HTTPS Analytics Daemon...");
        System.out.println("Monitoring log file: " + logFilePath);
        System.out.println("Using blacklist service: " + blacklistServiceUrl);

        daemon.start();
    }
}
