package com.library.repository;

import com.library.model.Book;
import com.library.model.Journal;
import com.library.model.Magazine;
import com.library.model.Media;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.core.RowMapper;
import org.springframework.jdbc.support.GeneratedKeyHolder;
import org.springframework.jdbc.support.KeyHolder;
import org.springframework.stereotype.Repository;
import org.springframework.transaction.annotation.Transactional;

import java.sql.PreparedStatement;
import java.sql.Statement;
import java.sql.Timestamp;
import java.time.LocalDate;
import java.util.List;
import java.util.Objects;
import java.util.Optional;
import java.util.concurrent.CompletableFuture;

@Repository
public class MediaRepository {

    private final JdbcTemplate jdbcTemplate;

    public MediaRepository(JdbcTemplate jdbcTemplate) {
        this.jdbcTemplate = jdbcTemplate;
    }

    @Transactional(readOnly = true)
    public CompletableFuture<List<Media>> findAll() {
        return CompletableFuture.supplyAsync(() -> {
            String sql = "SELECT * FROM media";
            return jdbcTemplate.query(sql, mediaRowMapper());
        });
    }

    @Transactional(readOnly = true)
    public CompletableFuture<Optional<Media>> findById(Long id) {
        return CompletableFuture.supplyAsync(() -> {
            String sql = "SELECT * FROM media WHERE id = ?";
            List<Media> results = jdbcTemplate.query(sql, mediaRowMapper(), id);
            return results.isEmpty() ? Optional.empty() : Optional.of(results.get(0));
        });
    }

    @Transactional
    public CompletableFuture<Media> save(Media media) {
        return CompletableFuture.supplyAsync(() -> {
            if (media.getId() == null) {
                return insert(media);
            } else {
                return update(media);
            }
        });
    }

    @Transactional
    public CompletableFuture<Boolean> deleteById(Long id) {
        return CompletableFuture.supplyAsync(() -> {
            String sql = "DELETE FROM media WHERE id = ?";
            int rowsAffected = jdbcTemplate.update(sql, id);
            return rowsAffected > 0;
        });
    }

    private Media insert(Media media) {
        KeyHolder keyHolder = new GeneratedKeyHolder();
        String sql = """
            INSERT INTO media (title, publisher, publication_date, isbn, media_type, 
            author, page_count, genre, academic_field, peer_reviewed, volume, issue, 
            category, is_monthly, issue_number) 
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """;

        jdbcTemplate.update(connection -> {
            PreparedStatement ps = connection.prepareStatement(sql, Statement.RETURN_GENERATED_KEYS);
            ps.setString(1, media.getTitle());
            ps.setString(2, media.getPublisher());
            ps.setTimestamp(3, Timestamp.valueOf(media.getPublicationDate().atStartOfDay()));
            ps.setString(4, media.getIsbn());
            ps.setString(5, media.getMediaType());

            if (media instanceof Book book) {
                ps.setString(6, book.getAuthor());
                ps.setInt(7, book.getPageCount());
                ps.setString(8, book.getGenre());
                ps.setNull(9, java.sql.Types.VARCHAR);
                ps.setNull(10, java.sql.Types.BOOLEAN);
                ps.setNull(11, java.sql.Types.INTEGER);
                ps.setNull(12, java.sql.Types.INTEGER);
                ps.setNull(13, java.sql.Types.VARCHAR);
                ps.setNull(14, java.sql.Types.BOOLEAN);
                ps.setNull(15, java.sql.Types.INTEGER);
            } else if (media instanceof Journal journal) {
                ps.setNull(6, java.sql.Types.VARCHAR);
                ps.setNull(7, java.sql.Types.INTEGER);
                ps.setNull(8, java.sql.Types.VARCHAR);
                ps.setString(9, journal.getAcademicField());
                ps.setBoolean(10, journal.isPeerReviewed());
                ps.setInt(11, journal.getVolume());
                ps.setInt(12, journal.getIssue());
                ps.setNull(13, java.sql.Types.VARCHAR);
                ps.setNull(14, java.sql.Types.BOOLEAN);
                ps.setNull(15, java.sql.Types.INTEGER);
            } else if (media instanceof Magazine magazine) {
                ps.setNull(6, java.sql.Types.VARCHAR);
                ps.setNull(7, java.sql.Types.INTEGER);
                ps.setNull(8, java.sql.Types.VARCHAR);
                ps.setNull(9, java.sql.Types.VARCHAR);
                ps.setNull(10, java.sql.Types.BOOLEAN);
                ps.setNull(11, java.sql.Types.INTEGER);
                ps.setNull(12, java.sql.Types.INTEGER);
                ps.setString(13, magazine.getCategory());
                ps.setBoolean(14, magazine.isMonthly());
                ps.setInt(15, magazine.getIssueNumber());
            }
            return ps;
        }, keyHolder);

        Long generatedId = Objects.requireNonNull(keyHolder.getKey()).longValue();
        media.setId(generatedId);
        return media;
    }

    private Media update(Media media) {
        String sql = """
            UPDATE media SET title = ?, publisher = ?, publication_date = ?, isbn = ?, media_type = ?, 
            author = ?, page_count = ?, genre = ?, academic_field = ?, peer_reviewed = ?, 
            volume = ?, issue = ?, category = ?, is_monthly = ?, issue_number = ? 
            WHERE id = ?
            """;

        if (media instanceof Book book) {
            jdbcTemplate.update(sql, 
                book.getTitle(), 
                book.getPublisher(),
                Timestamp.valueOf(book.getPublicationDate().atStartOfDay()),
                book.getIsbn(),
                book.getMediaType(),
                book.getAuthor(),
                book.getPageCount(),
                book.getGenre(),
                null, null, null, null, null, null, null,
                book.getId()
            );
        } else if (media instanceof Journal journal) {
            jdbcTemplate.update(sql, 
                journal.getTitle(), 
                journal.getPublisher(),
                Timestamp.valueOf(journal.getPublicationDate().atStartOfDay()),
                journal.getIsbn(),
                journal.getMediaType(),
                null, null, null,
                journal.getAcademicField(),
                journal.isPeerReviewed(),
                journal.getVolume(),
                journal.getIssue(),
                null, null, null,
                journal.getId()
            );
        } else if (media instanceof Magazine magazine) {
            jdbcTemplate.update(sql, 
                magazine.getTitle(), 
                magazine.getPublisher(),
                Timestamp.valueOf(magazine.getPublicationDate().atStartOfDay()),
                magazine.getIsbn(),
                magazine.getMediaType(),
                null, null, null, null, null, null, null,
                magazine.getCategory(),
                magazine.isMonthly(),
                magazine.getIssueNumber(),
                magazine.getId()
            );
        }
        return media;
    }

    private RowMapper<Media> mediaRowMapper() {
        return (rs, rowNum) -> {
            Long id = rs.getLong("id");
            String title = rs.getString("title");
            String publisher = rs.getString("publisher");
            LocalDate publicationDate = rs.getTimestamp("publication_date").toLocalDateTime().toLocalDate();
            String isbn = rs.getString("isbn");
            String mediaType = rs.getString("media_type");

            return switch (mediaType) {
                case "BOOK" -> new Book(
                    id, title, publisher, publicationDate, isbn,
                    rs.getString("author"),
                    rs.getInt("page_count"),
                    rs.getString("genre")
                );
                case "JOURNAL" -> new Journal(
                    id, title, publisher, publicationDate, isbn,
                    rs.getString("academic_field"),
                    rs.getBoolean("peer_reviewed"),
                    rs.getInt("volume"),
                    rs.getInt("issue")
                );
                case "MAGAZINE" -> new Magazine(
                    id, title, publisher, publicationDate, isbn,
                    rs.getString("category"),
                    rs.getBoolean("is_monthly"),
                    rs.getInt("issue_number")
                );
                default -> throw new IllegalStateException("Unexpected media type: " + mediaType);
            };
        };
    }
}
