package com.library.service;

import com.library.dto.MediaDTO;
import com.library.model.Book;
import com.library.model.Journal;
import com.library.model.Magazine;
import com.library.model.Media;
import com.library.repository.MediaRepository;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.NoSuchElementException;
import java.util.concurrent.CompletableFuture;

@Service
public class MediaService {

    private final MediaRepository mediaRepository;

    public MediaService(MediaRepository mediaRepository) {
        this.mediaRepository = mediaRepository;
    }

    public CompletableFuture<List<MediaDTO>> getAllMedia() {
        return mediaRepository.findAll()
            .thenApply(mediaList -> mediaList.stream()
                .map(this::convertToDTO)
                .toList());
    }

    public CompletableFuture<MediaDTO> getMediaById(Long id) {
        return mediaRepository.findById(id)
            .thenApply(mediaOptional -> mediaOptional
                .map(this::convertToDTO)
                .orElseThrow(() -> new NoSuchElementException("Media not found with id: " + id)));
    }

    public CompletableFuture<MediaDTO> createMedia(MediaDTO mediaDTO) {
        Media media = convertToEntity(mediaDTO);
        return mediaRepository.save(media)
            .thenApply(this::convertToDTO);
    }

    public CompletableFuture<MediaDTO> updateMedia(Long id, MediaDTO mediaDTO) {
        return mediaRepository.findById(id)
            .thenCompose(optionalMedia -> {
                if (optionalMedia.isEmpty()) {
                    throw new NoSuchElementException("Media not found with id: " + id);
                }
                Media media = convertToEntity(mediaDTO);
                media.setId(id);
                return mediaRepository.save(media);
            })
            .thenApply(this::convertToDTO);
    }

    public CompletableFuture<Void> deleteMedia(Long id) {
        return mediaRepository.deleteById(id)
            .thenAccept(deleted -> {
                if (!deleted) {
                    throw new NoSuchElementException("Media not found with id: " + id);
                }
            });
    }

    private MediaDTO convertToDTO(Media media) {
        if (media instanceof Book book) {
            return new MediaDTO(
                book.getId(), book.getTitle(), book.getPublisher(), book.getPublicationDate(), book.getIsbn(), 
                book.getMediaType(), book.getAuthor(), book.getPageCount(), book.getGenre(),
                null, null, null, null, null, null, null
            );
        } else if (media instanceof Journal journal) {
            return new MediaDTO(
                journal.getId(), journal.getTitle(), journal.getPublisher(), journal.getPublicationDate(), journal.getIsbn(), 
                journal.getMediaType(), null, null, null,
                journal.getAcademicField(), journal.isPeerReviewed(), journal.getVolume(), journal.getIssue(),
                null, null, null
            );
        } else if (media instanceof Magazine magazine) {
            return new MediaDTO(
                magazine.getId(), magazine.getTitle(), magazine.getPublisher(), magazine.getPublicationDate(), magazine.getIsbn(), 
                magazine.getMediaType(), null, null, null,
                null, null, null, null,
                magazine.getCategory(), magazine.isMonthly(), magazine.getIssueNumber()
            );
        } else {
            throw new IllegalArgumentException("Unknown media type");
        }
    }

    private Media convertToEntity(MediaDTO dto) {
        return switch (dto.mediaType()) {
            case "BOOK" -> new Book(
                dto.id(), dto.title(), dto.publisher(), dto.publicationDate(), dto.isbn(),
                dto.author(), dto.pageCount(), dto.genre()
            );
            case "JOURNAL" -> new Journal(
                dto.id(), dto.title(), dto.publisher(), dto.publicationDate(), dto.isbn(),
                dto.academicField(), dto.peerReviewed(), dto.volume(), dto.issue()
            );
            case "MAGAZINE" -> new Magazine(
                dto.id(), dto.title(), dto.publisher(), dto.publicationDate(), dto.isbn(),
                dto.category(), dto.isMonthly(), dto.issueNumber()
            );
            default -> throw new IllegalArgumentException("Invalid media type: " + dto.mediaType());
        };
    }
}
