import java.util.concurrent.CompletableFuture;

@Component
public class LibraryHttpClient {

    private final HttpClient httpClient;
    private final String baseUrl = "http://localhost:8080/api/media";

    public LibraryHttpClient() {
        this.httpClient = HttpClient.newBuilder()
            .version(HttpClient.Version.HTTP_2)
            .connectTimeout(Duration.ofSeconds(10))
            .build();
    }

    public CompletableFuture<String> getAllMedia() {
        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create(baseUrl))
            .GET()
            .header("Accept", "application/json")
            .build();

        return httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
            .thenApply(HttpResponse::body);
    }

    public CompletableFuture<String> getMediaById(Long id) {
        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create(baseUrl + "/" + id))
            .GET()
            .header("Accept", "application/json")
            .build();

        return httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
            .thenApply(HttpResponse::body);
    }

    public CompletableFuture<String> createMedia(String jsonMedia) {
        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create(baseUrl))
            .POST(HttpRequest.BodyPublishers.ofString(jsonMedia))
            .header("Content-Type", "application/json")
            .build();

        return httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
            .thenApply(HttpResponse::body);
    }

    public CompletableFuture<String> updateMedia(Long id, String jsonMedia) {
        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create(baseUrl + "/" + id))
            .PUT(HttpRequest.BodyPublishers.ofString(jsonMedia))
            .header("Content-Type", "application/json")
            .build();

        return httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
            .thenApply(HttpResponse::body);
    }

    public CompletableFuture<Integer> deleteMedia(Long id) {
        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create(baseUrl + "/" + id))
            .DELETE()
            .build();

        return httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
            .thenApply(HttpResponse::statusCode);
    }
}
