Here's a Rust CLI tool that monitors a directory for file changes using asynchronous event handling:

```rust
use notify::{Config, Event, RecommendedWatcher, RecursiveMode, Watcher};
use sha2::{Digest, Sha256};
use std::fs::{self, File};
use std::io::{Read, Write};
use std::path::{Path, PathBuf};
use std::sync::mpsc::channel;
use std::time::{SystemTime, UNIX_EPOCH};
use structopt::StructOpt;
use tokio::runtime::Runtime;

#[derive(StructOpt, Debug)]
#[structopt(name = "file-monitor", about = "Monitors a directory for file changes.")]
struct Opt {
    /// Directory to monitor
    #[structopt(short, long, parse(from_os_str))]
    directory: PathBuf,

    /// Log file path
    #[structopt(short, long, parse(from_os_str), default_value = "file_changes.log")]
    log_file: PathBuf,
}

async fn process_event(event: Event, log_file: PathBuf) {
    let timestamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_secs();

    for path in event.paths {
        if path.is_file() {
            let file_name = path.file_name().unwrap().to_string_lossy();

            // Calculate SHA256 hash
            let hash = match calculate_hash(&path) {
                Ok(hash) => hash,
                Err(e) => {
                    eprintln!("Error calculating hash for {:?}: {}", path, e);
                    String::from("hash_calculation_failed")
                }
            };

            let log_entry = format!(
                "[{}] File: {}, Event: {:?}, Hash: {}\n",
                timestamp,
                file_name,
                event.kind,
                hash
            );

            // Log the change
            match fs::OpenOptions::new()
                .create(true)
                .append(true)
                .open(&log_file)
            {
                Ok(mut file) => {
                    if let Err(e) = file.write_all(log_entry.as_bytes()) {
                        eprintln!("Error writing to log file: {}", e);
                    }
                }
                Err(e) => eprintln!("Error opening log file: {}", e),
            }

            println!("Processed: {}", file_name);
        }
    }
}

fn calculate_hash<P: AsRef<Path>>(path: P) -> Result<String, std::io::Error> {
    let mut file = File::open(path)?;
    let mut buffer = Vec::new();
    file.read_to_end(&mut buffer)?;

    let mut hasher = Sha256::new();
    hasher.update(&buffer);
    let result = hasher.finalize();

    Ok(format!("{:x}", result))
}

fn main() {
    let opt = Opt::from_args();

    // Create a tokio runtime
    let rt = Runtime::new().unwrap();

    // Set up the channel for the watcher to send events
    let (tx, rx) = channel();

    // Create and configure the watcher
    let mut watcher = RecommendedWatcher::new(tx, Config::default()).unwrap();

    // Start watching the directory
    watcher.watch(&opt.directory, RecursiveMode::Recursive).unwrap();

    println!("Monitoring directory: {:?}", opt.directory);
    println!("Log file: {:?}", opt.log_file);

    // Process events
    for res in rx {
        match res {
            Ok(event) => {
                let log_file = opt.log_file.clone();
                rt.block_on(process_event(event, log_file));
            }
            Err(e) => eprintln!("Watch error: {:?}", e),
        }
    }
}
