package com.rssprocessor;

import com.rssprocessor.db.DatabaseManager;
import com.rssprocessor.model.Feed;
import com.rssprocessor.processor.FeedProcessor;

import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class Main {
    public static void main(String[] args) {
        // Initialize database
        DatabaseManager.initDatabase();

        // List of RSS feed URLs to process
        List<String> feedUrls = List.of(
                "https://news.google.com/rss",
                "https://rss.nytimes.com/services/xml/rss/nyt/World.xml",
                "https://feeds.bbci.co.uk/news/world/rss.xml"
        );

        // Using structured concurrency with virtual threads (JDK 21 feature)
        // If using JDK 17, can use ExecutorService with standard thread pool instead
        try (ExecutorService executor = Executors.newVirtualThreadPerTaskExecutor()) {
            for (String url : feedUrls) {
                executor.submit(() -> {
                    try {
                        Feed feed = FeedProcessor.fetchAndParseFeed(url);
                        DatabaseManager.storeFeedItems(feed.items());
                        System.out.println("Processed: " + url + " - Items: " + feed.items().size());
                    } catch (Exception e) {
                        System.err.println("Error processing feed " + url + ": " + e.getMessage());
                    }
                });
            }
        }
    }
