package com.rssprocessor.processor;

import com.rssprocessor.model.Feed;
import com.rssprocessor.model.FeedItem;
import com.rssprocessor.model.RssChannel;
import com.rssprocessor.model.RssElement;
import com.rssprocessor.model.RssItem;

import javax.xml.stream.XMLEventReader;
import javax.xml.stream.XMLInputFactory;
import javax.xml.stream.events.XMLEvent;
import java.io.InputStream;
import java.net.HttpURLConnection;
import java.net.URL;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;

public class FeedProcessor {

    public static Feed fetchAndParseFeed(String urlString) throws Exception {
        URL url = new URL(urlString);
        HttpURLConnection connection = (HttpURLConnection) url.openConnection();
        connection.setRequestMethod("GET");

        try (InputStream inputStream = connection.getInputStream()) {
            return parseFeed(inputStream, urlString);
        } finally {
            connection.disconnect();
        }
    }

    private static Feed parseFeed(InputStream inputStream, String sourceUrl) throws Exception {
        XMLInputFactory inputFactory = XMLInputFactory.newInstance();
        XMLEventReader eventReader = inputFactory.createXMLEventReader(inputStream);

        String title = "";
        String link = "";
        List<FeedItem> items = new ArrayList<>();

        String currentElement = "";
        String currentTitle = "";
        String currentLink = "";
        String currentPubDate = "";
        boolean inItem = false;

        while (eventReader.hasNext()) {
            XMLEvent event = eventReader.nextEvent();

            if (event.isStartElement()) {
                String localName = event.asStartElement().getName().getLocalPart();
                currentElement = localName;

                switch (localName) {
                    case "item" -> inItem = true;
                    case "channel" -> {
                        if (!inItem) {
                            // Process channel data
                        }
                    }
                }
            } else if (event.isEndElement()) {
                String localName = event.asEndElement().getName().getLocalPart();

                if ("item".equals(localName)) {
                    // Using pattern matching with switch (JDK 17 feature)
                    RssElement element = new RssItem(currentTitle, currentLink, "", currentPubDate);

                    switch (element) {
                        case RssItem item when !item.title().isEmpty() && !item.pubDate().isEmpty() -> {
                            LocalDateTime pubDateTime = parseDate(item.pubDate());
                            items.add(new FeedItem(item.title(), item.link(), pubDateTime, sourceUrl));
                        }
                        case RssChannel channel -> {
                            title = channel.title();
                            link = channel.link();
                        }
                        default -> { /* Ignore incomplete entries */ }
                    }

                    currentTitle = "";
                    currentLink = "";
                    currentPubDate = "";
                    inItem = false;
                }

                currentElement = "";
            } else if (event.isCharacters() && event.asCharacters().getData().trim().length() > 0) {
                String data = event.asCharacters().getData();

                if (inItem) {
                    switch (currentElement) {
                        case "title" -> currentTitle = data;
                        case "link" -> currentLink = data;
                        case "pubDate" -> currentPubDate = data;
                    }
                } else {
                    switch (currentElement) {
                        case "title" -> title = data;
                        case "link" -> link = data;
                    }
                }
            }
        }

        return new Feed(title, link, items);
    }

    private static LocalDateTime parseDate(String dateStr) {
        try {
            // Simple date parsing logic - would need to be expanded for various RSS date formats
            DateTimeFormatter formatter = DateTimeFormatter.RFC_1123_DATE_TIME;
            return LocalDateTime.parse(dateStr, formatter);
        } catch (Exception e) {
            return LocalDateTime.now(); // Fallback to current time if parsing fails
        }
    }
}
