package com.rssprocessor.db;

import com.rssprocessor.model.FeedItem;

import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.SQLException;
import java.sql.Statement;
import java.sql.Timestamp;
import java.util.List;

public class DatabaseManager {
    private static final String DB_URL = "jdbc:sqlite:rss_feeds.db";

    public static void initDatabase() {
        try (Connection conn = DriverManager.getConnection(DB_URL);
             Statement stmt = conn.createStatement()) {

            // Create table if it doesn't exist
            String sql = """
                CREATE TABLE IF NOT EXISTS feed_items (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    title TEXT NOT NULL,
                    link TEXT NOT NULL,
                    publication_date TIMESTAMP,
                    source TEXT,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            """;

            stmt.execute(sql);
            System.out.println("Database initialized successfully");

        } catch (SQLException e) {
            System.err.println("Database initialization error: " + e.getMessage());
        }
    }

    public static void storeFeedItems(List<FeedItem> items) {
        String sql = """
            INSERT INTO feed_items (title, link, publication_date, source)
            VALUES (?, ?, ?, ?)
        """;

        try (Connection conn = DriverManager.getConnection(DB_URL);
             PreparedStatement pstmt = conn.prepareStatement(sql)) {

            conn.setAutoCommit(false);

            for (FeedItem item : items) {
                pstmt.setString(1, item.title());
                pstmt.setString(2, item.link());
                pstmt.setTimestamp(3, Timestamp.valueOf(item.pubDate()));
                pstmt.setString(4, item.source());
                pstmt.addBatch();
            }

            pstmt.executeBatch();
            conn.commit();

        } catch (SQLException e) {
            System.err.println("Error storing feed items: " + e.getMessage());
        }
    }
}
