Here's a Rust-based command-line application for database migrations:

```rust:src/main.rs
use async_std::task;
use clap::{App, Arg};
use diesel::prelude::*;
use diesel::pg::PgConnection;
use diesel::connection::Connection as DieselConnection;
use diesel::result::Error as DieselError;
use dotenv::dotenv;
use std::env;
use std::fs;
use std::path::Path;
use std::time::SystemTime;
use chrono::Utc;

mod schema {
    table! {
        migration_history (id) {
            id -> Integer,
            filename -> Text,
            applied_at -> Timestamp,
            success -> Bool,
        }
    }
}

use schema::migration_history;

#[derive(Insertable)]
#[table_name = "migration_history"]
struct NewMigration<'a> {
    filename: &'a str,
    applied_at: chrono::NaiveDateTime,
    success: bool,
}

#[derive(Queryable)]
struct Migration {
    id: i32,
    filename: String,
    applied_at: chrono::NaiveDateTime,
    success: bool,
}

fn establish_connection() -> PgConnection {
    dotenv().ok();

    let database_url = env::var("DATABASE_URL")
        .expect("DATABASE_URL must be set");

    PgConnection::establish(&database_url)
        .expect(&format!("Error connecting to {}", database_url))
}

fn create_migration_table_if_not_exists(conn: &PgConnection) -> Result<(), DieselError> {
    conn.execute("
        CREATE TABLE IF NOT EXISTS migration_history (
            id SERIAL PRIMARY KEY,
            filename TEXT NOT NULL,
            applied_at TIMESTAMP NOT NULL,
            success BOOLEAN NOT NULL
        )
    ")?;

    Ok(())
}

fn get_applied_migrations(conn: &PgConnection) -> Result<Vec<String>, DieselError> {
    use schema::migration_history::dsl::*;

    let results = migration_history
        .filter(success.eq(true))
        .select(filename)
        .load::<String>(conn)?;

    Ok(results)
}

fn apply_migration(conn: &PgConnection, file_path: &Path) -> Result<(), DieselError> {
    let file_name = file_path.file_name()
        .unwrap()
        .to_str()
        .unwrap();

    println!("Applying migration: {}", file_name);

    let sql = fs::read_to_string(file_path)
        .expect(&format!("Could not read migration file: {}", file_name));

    conn.transaction::<_, DieselError, _>(|| {
        // Apply the migration
        conn.batch_execute(&sql)?;

        // Record the migration
        let new_migration = NewMigration {
            filename: file_name,
            applied_at: Utc::now().naive_utc(),
            success: true,
        };

        diesel::insert_into(migration_history::table)
            .values(&new_migration)
            .execute(conn)?;

        Ok(())
    })
}

fn main() {
    let matches = App::new("Rust DB Migrator")
        .version("1.0")
        .author("Your Name")
        .about("PostgreSQL database migration tool")
        .arg(Arg::with_name("migrations-dir")
            .short("d")
            .long("dir")
            .value_name("DIRECTORY")
            .help("Directory containing migration files")
            .takes_value(true)
            .required(true))
        .get_matches();

    let migrations_dir = matches.value_of("migrations-dir").unwrap();

    task::block_on(async {
        let conn = establish_connection();

        // Create migration history table if it doesn't exist
        match create_migration_table_if_not_exists(&conn) {
            Ok(_) => println!("Migration table ready"),
            Err(e) => {
                eprintln!("Failed to create migration table: {}", e);
                return;
            }
        }

        // Get already applied migrations
        let applied_migrations = match get_applied_migrations(&conn) {
            Ok(migrations) => migrations,
            Err(e) => {
                eprintln!("Failed to get applied migrations: {}", e);
                return;
            }
        };

        // Read migration files
        let mut migration_files = Vec::new();
        match fs::read_dir(migrations_dir) {
            Ok(entries) => {
                for entry in entries {
                    if let Ok(entry) = entry {
                        let path = entry.path();
                        if path.is_file() && path.extension().and_then(|s| s.to_str()) == Some("sql") {
                            migration_files.push(path);
                        }
                    }
                }
            },
            Err(e) => {
                eprintln!("Failed to read migrations directory: {}", e);
                return;
            }
        }

        // Sort migration files by name
        migration_files.sort_by(|a, b| a.file_name().unwrap().cmp(b.file_name().unwrap()));

        // Apply migrations
        for file_path in migration_files {
            let file_name = file_path.file_name().unwrap().to_str().unwrap();

            // Skip if already applied
            if applied_migrations.contains(&file_name.to_string()) {
                println!("Migration {} already applied, skipping", file_name);
                continue;
            }

            // Apply the migration
            match apply_migration(&conn, &file_path) {
                Ok(_) => println!("Successfully applied migration: {}", file_name),
                Err(e) => {
                    eprintln!("Failed to apply migration {}: {}", file_name, e);

                    // Record the failure
                    let new_migration = NewMigration {
                        filename: file_name,
                        applied_at: Utc::now().naive_utc(),
                        success: false,
                    };

                    if let Err(e) = diesel::insert_into(migration_history::table)
                        .values(&new_migration)
                        .execute(&conn) {
                        eprintln!("Failed to record migration failure: {}", e);
                    }

                    return;
                }
            }
        }

        println!("All migrations applied successfully!");
    });
}
