Here's a Java logging tool for monitoring config files:

```java
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ObjectNode;

import java.io.IOException;
import java.nio.file.*;
import java.nio.file.attribute.BasicFileAttributes;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.TimeUnit;

public class ConfigFileMonitor {
    private final WatchService watchService;
    private final Map<WatchKey, Path> watchKeys = new HashMap<>();
    private final Path logFilePath;
    private final ObjectMapper objectMapper = new ObjectMapper();
    private final DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");

    public ConfigFileMonitor(Path logFilePath) throws IOException {
        this.watchService = FileSystems.getDefault().newWatchService();
        this.logFilePath = logFilePath;
    }

    public void registerDirectory(Path directory) throws IOException {
        if (!Files.isDirectory(directory)) {
            throw new IllegalArgumentException(directory + " is not a directory");
        }

        // Register the directory
        WatchKey key = directory.register(watchService,
                StandardWatchEventKinds.ENTRY_CREATE,
                StandardWatchEventKinds.ENTRY_DELETE,
                StandardWatchEventKinds.ENTRY_MODIFY);
        watchKeys.put(key, directory);

        // Log the registration
        logEvent("REGISTER", directory.toString(), "Directory registered for monitoring");
    }

    public void watchConfigFiles() {
        System.out.println("Config file monitoring started. Watching for changes...");

        try {
            while (true) {
                WatchKey key;
                try {
                    key = watchService.poll(10, TimeUnit.SECONDS);
                    if (key == null) {
                        continue;
                    }
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                    break;
                }

                Path dir = watchKeys.get(key);
                if (dir == null) {
                    System.err.println("WatchKey not recognized!");
                    continue;
                }

                for (WatchEvent<?> event : key.pollEvents()) {
                    WatchEvent.Kind<?> kind = event.kind();

                    if (kind == StandardWatchEventKinds.OVERFLOW) {
                        continue;
                    }

                    // Get the filename of the event
                    @SuppressWarnings("unchecked")
                    WatchEvent<Path> ev = (WatchEvent<Path>) event;
                    Path filename = ev.context();
                    Path fullPath = dir.resolve(filename);

                    // Only process text-based config files
                    if (isConfigFile(fullPath)) {
                        String eventType = getEventType(kind);
                        String details = getFileDetails(fullPath, kind);
                        logEvent(eventType, fullPath.toString(), details);
                    }
                }

                // Reset the key - required to receive further watch events
                boolean valid = key.reset();
                if (!valid) {
                    watchKeys.remove(key);
                    if (watchKeys.isEmpty()) {
                        break;
                    }
                }
            }
        } catch (IOException e) {
            System.err.println("Error during file monitoring: " + e.getMessage());
        }
    }

    private boolean isConfigFile(Path path) {
        if (!Files.exists(path)) {
            return true; // For deleted files, we'll assume it was a config file
        }

        String fileName = path.getFileName().toString().toLowerCase();
        String[] configExtensions = {".properties", ".xml", ".json", ".yaml", ".yml", ".conf", ".cfg", ".ini", ".config"};

        for (String ext : configExtensions) {
            if (fileName.endsWith(ext)) {
                return true;
            }
        }

        return false;
    }

    private String getEventType(WatchEvent.Kind<?> kind) {
        if (kind == StandardWatchEventKinds.ENTRY_CREATE) {
            return "CREATE";
        } else if (kind == StandardWatchEventKinds.ENTRY_DELETE) {
            return "DELETE";
        } else if (kind == StandardWatchEventKinds.ENTRY_MODIFY) {
            return "MODIFY";
        } else {
            return "UNKNOWN";
        }
    }

    private String getFileDetails(Path path, WatchEvent.Kind<?> kind) throws IOException {
        if (kind == StandardWatchEventKinds.ENTRY_DELETE) {
            return "File was deleted";
        }

        try {
            BasicFileAttributes attrs = Files.readAttributes(path, BasicFileAttributes.class);
            return String.format("Size: %d bytes, Last modified: %s, Creation time: %s",
                    attrs.size(),
                    attrs.lastModifiedTime(),
                    attrs.creationTime());
        } catch (IOException e) {
            return "Unable to read file attributes";
        }
    }

    private void logEvent(String eventType, String filePath, String details) throws IOException {
        ObjectNode jsonLog = objectMapper.createObjectNode();
        jsonLog.put("timestamp", LocalDateTime.now().format(formatter));
        jsonLog.put("eventType", eventType);
        jsonLog.put("filePath", filePath);
        jsonLog.put("details", details);

        String jsonEntry = objectMapper.writerWithDefaultPrettyPrinter().writeValueAsString(jsonLog) + System.lineSeparator();

        // Append to log file
        Files.write(logFilePath, jsonEntry.getBytes(), 
                StandardOpenOption.CREATE, 
                StandardOpenOption.APPEND);

        // Also print to console
        System.out.println(jsonEntry);
    }

    public static void main(String[] args) {
        if (args.length < 2) {
            System.out.println("Usage: java ConfigFileMonitor <log-file-path> <directory-to-monitor> [directory2] [directory3] ...");
            System.exit(1);
        }

        try {
            Path logFile = Paths.get(args[0]);
            ConfigFileMonitor monitor = new ConfigFileMonitor(logFile);

            // Register all directories specified in the arguments
            for (int i = 1; i < args.length; i++) {
                Path directory = Paths.get(args[i]);
                monitor.registerDirectory(directory);
                System.out.println("Monitoring directory: " + directory);
            }

            // Start watching for changes
            monitor.watchConfigFiles();
        } catch (IOException e) {
            System.err.println("Error setting up file monitor: " + e.getMessage());
            e.printStackTrace();
        }
    }
}
```

