I'll create a Java application that monitors web server health as specified. Here's the implementation:

```java:ServerHealthMonitor.java
package com.servermonitor;

import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.time.Duration;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;
import java.util.Properties;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;
import java.util.logging.FileHandler;
import java.util.logging.Logger;
import java.util.logging.SimpleFormatter;

public class ServerHealthMonitor {
    private static final Logger LOGGER = Logger.getLogger(ServerHealthMonitor.class.getName());
    private final List<String> urls;
    private final int intervalSeconds;
    private final HttpClient httpClient;
    private final ScheduledExecutorService scheduler;

    public ServerHealthMonitor(String configFilePath) throws IOException {
        // Load configuration
        Properties config = new Properties();
        config.load(Files.newInputStream(Paths.get(configFilePath)));

        // Parse URLs
        String urlsString = config.getProperty("urls");
        urls = new ArrayList<>();
        for (String url : urlsString.split(",")) {
            urls.add(url.trim());
        }

        // Parse interval
        intervalSeconds = Integer.parseInt(config.getProperty("interval.seconds", "60"));

        // Set up HTTP client
        httpClient = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(10))
                .build();

        // Set up scheduler
        scheduler = Executors.newScheduledThreadPool(1);

        // Set up logging
        setupLogging();
    }

    private void setupLogging() {
        try {
            FileHandler fileHandler = new FileHandler("server_health.log", true);
            SimpleFormatter formatter = new SimpleFormatter();
            fileHandler.setFormatter(formatter);
            LOGGER.addHandler(fileHandler);
        } catch (IOException e) {
            System.err.println("Failed to set up logging: " + e.getMessage());
        }
    }

    public void start() {
        LOGGER.info("Starting server health monitoring for " + urls.size() + " URLs with interval of " + 
                intervalSeconds + " seconds");

        scheduler.scheduleAtFixedRate(this::checkServers, 0, intervalSeconds, TimeUnit.SECONDS);
    }

    private void checkServers() {
        List<CompletableFuture<Void>> futures = new ArrayList<>();

        for (String url : urls) {
            CompletableFuture<Void> future = checkServerHealth(url)
                    .exceptionally(ex -> {
                        String errorMsg = "Exception while monitoring " + url + ": " + ex.getMessage();
                        LOGGER.severe(errorMsg);
                        sendAlert(url, errorMsg);
                        return null;
                    });
            futures.add(future);
        }

        // Wait for all requests to complete
        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0])).join();
    }

    private CompletableFuture<Void> checkServerHealth(String url) {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(url))
                .timeout(Duration.ofSeconds(10))
                .GET()
                .build();

        return httpClient.sendAsync(request, HttpResponse.BodyHandlers.ofString())
                .thenApply(response -> {
                    int statusCode = response.statusCode();
                    String timestamp = LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME);
                    String logMessage = String.format("[%s] %s - Status: %d", timestamp, url, statusCode);

                    if (statusCode >= 200 && statusCode < 300) {
                        LOGGER.info(logMessage + " - OK");
                    } else {
                        LOGGER.warning(logMessage + " - ERROR");
                        sendAlert(url, "Server returned status code: " + statusCode);
                    }
                    return response;
                })
                .thenCompose(response -> CompletableFuture.completedFuture(null));
    }

    private void sendAlert(String url, String message) {
        // In a real application, this could send an email, SMS, etc.
        System.err.println("ALERT: " + url + " - " + message);
        LOGGER.severe("ALERT: " + url + " - " + message);
    }

    public void stop() {
        LOGGER.info("Stopping server health monitoring");
        scheduler.shutdown();
        try {
            if (!scheduler.awaitTermination(60, TimeUnit.SECONDS)) {
                scheduler.shutdownNow();
            }
        } catch (InterruptedException e) {
            scheduler.shutdownNow();
            Thread.currentThread().interrupt();
        }
    }
}
