```java:Main.java
package com.servermonitor;

import java.io.IOException;

public class Main {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.out.println("Usage: java -jar server-monitor.jar <config-file-path>");
            System.exit(1);
        }

        String configFilePath = args[0];

        try {
            ServerHealthMonitor monitor = new ServerHealthMonitor(configFilePath);

            // Add shutdown hook to properly stop the monitor
            Runtime.getRuntime().addShutdownHook(new Thread(monitor::stop));

            // Start monitoring
            monitor.start();

            // Keep the application running
            Thread.currentThread().join();
        } catch (IOException e) {
            System.err.println("Failed to initialize server monitor: " + e.getMessage());
            System.exit(1);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }
}
