I'll create a multi-threaded Rust application for asynchronous web scraping. Here's the code:

```rust:src/main.rs
use futures::stream::{self, StreamExt};
use reqwest::Client;
use scraper::{Html, Selector};
use std::collections::HashMap;
use std::io::{self, BufRead};
use std::sync::Arc;
use tokio::sync::Mutex;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Create a shared client for all requests
    let client = Arc::new(Client::new());

    // Create a shared HashMap to store results
    let results = Arc::new(Mutex::new(HashMap::new()));

    // Read URLs from stdin
    let stdin = io::stdin();
    let mut urls: Vec<String> = Vec::new();

    for line in stdin.lock().lines() {
        urls.push(line?);
    }

    // Process URLs concurrently
    stream::iter(urls)
        .map(|url| {
            let client = Arc::clone(&client);
            let results = Arc::clone(&results);

            tokio::spawn(async move {
                match process_url(&url, &client).await {
                    Ok(title) => {
                        let mut results = results.lock().await;
                        results.insert(url, title);
                    }
                    Err(e) => {
                        eprintln!("Error processing {}: {}", url, e);
                    }
                }
            })
        })
        .buffer_unordered(10) // Process up to 10 URLs concurrently
        .collect::<Vec<_>>()
        .await;

    // Print the results
    let final_results = results.lock().await;
    println!("{:#?}", *final_results);

    Ok(())
}

async fn process_url(url: &str, client: &Client) -> Result<String, Box<dyn std::error::Error + Send + Sync>> {
    // Fetch the URL content
    let response = client.get(url).send().await?;
    let body = response.text().await?;

    // Parse the HTML
    let document = Html::parse_document(&body);
    let selector = Selector::parse("title").unwrap();

    // Extract the title
    if let Some(title_element) = document.select(&selector).next() {
        Ok(title_element.inner_html())
    } else {
        Ok(String::from("No title found"))
    }
}
