```rust:src/main.rs
use log::{error, info};
use serde::{Deserialize, Serialize};
use std::error::Error;
use tokio::io::{AsyncReadExt, AsyncWriteExt};
use tokio::net::{TcpListener, TcpStream};

#[derive(Debug, Deserialize)]
struct Request {
    data: String,
    operation: String,
}

#[derive(Debug, Serialize)]
struct Response {
    result: String,
    status: String,
}

async fn process_data(data: &str, operation: &str) -> String {
    // Custom business logic implementation
    match operation {
        "uppercase" => data.to_uppercase(),
        "lowercase" => data.to_lowercase(),
        "reverse" => data.chars().rev().collect(),
        _ => format!("Unknown operation: {}", operation),
    }
}

async fn handle_client(mut socket: TcpStream) -> Result<(), Box<dyn Error>> {
    let mut buffer = Vec::new();

    // Read data from the client
    socket.read_to_end(&mut buffer).await?;

    // Deserialize JSON
    let request: Request = match serde_json::from_slice(&buffer) {
        Ok(req) => req,
        Err(e) => {
            error!("Failed to parse JSON: {}", e);
            let error_response = Response {
                result: "".to_string(),
                status: format!("Error: Invalid JSON - {}", e),
            };
            let json = serde_json::to_string(&error_response)?;
            socket.write_all(json.as_bytes()).await?;
            return Err(e.into());
        }
    };

    info!("Received request: {:?}", request);

    // Process the data
    let result = process_data(&request.data, &request.operation).await;

    // Prepare and send response
    let response = Response {
        result,
        status: "success".to_string(),
    };

    let json = serde_json::to_string(&response)?;
    socket.write_all(json.as_bytes()).await?;

    info!("Response sent successfully");
    Ok(())
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    // Initialize logger
    env_logger::init();

    let port = std::env::var("PORT").unwrap_or_else(|_| "8080".to_string());
    let addr = format!("127.0.0.1:{}", port);

    // Create a TCP listener
    let listener = TcpListener::bind(&addr).await?;
    info!("Server listening on {}", addr);

    // Accept connections
    loop {
        match listener.accept().await {
            Ok((socket, addr)) => {
                info!("New connection from: {}", addr);

                // Spawn a new task for each connection
                tokio::spawn(async move {
                    if let Err(e) = handle_client(socket).await {
                        error!("Error handling client: {}", e);
                    }
                });
            }
            Err(e) => {
                error!("Failed to accept connection: {}", e);
            }
        }
    }
}
