Here's a Java service using JDK 17 that processes e-commerce transactions from Kafka:

```java
package com.ecommerce.service;

import com.fasterxml.jackson.databind.ObjectMapper;
import org.apache.kafka.clients.consumer.ConsumerConfig;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.KafkaConsumer;
import org.apache.kafka.common.serialization.StringDeserializer;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.datasource.DataSourceTransactionManager;
import org.springframework.transaction.PlatformTransactionManager;
import org.springframework.transaction.TransactionStatus;
import org.springframework.transaction.support.TransactionCallback;
import org.springframework.transaction.support.TransactionTemplate;

import javax.sql.DataSource;
import java.time.Duration;
import java.util.Collections;
import java.util.Properties;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

@SpringBootApplication
public class TransactionProcessorService {

    public static void main(String[] args) {
        SpringApplication.run(TransactionProcessorService.class, args);
    }

    @Bean
    public PlatformTransactionManager transactionManager(DataSource dataSource) {
        return new DataSourceTransactionManager(dataSource);
    }

    @Bean
    public TransactionTemplate transactionTemplate(PlatformTransactionManager transactionManager) {
        return new TransactionTemplate(transactionManager);
    }

    @Bean
    public KafkaConsumer<String, String> kafkaConsumer(@Value("${kafka.bootstrap.servers}") String bootstrapServers,
                                                      @Value("${kafka.group.id}") String groupId) {
        Properties props = new Properties();
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ConsumerConfig.GROUP_ID_CONFIG, groupId);
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
        return new KafkaConsumer<>(props);
    }

    @Bean
    public ExecutorService processingExecutor() {
        return Executors.newFixedThreadPool(Runtime.getRuntime().availableProcessors());
    }

    @Bean
    public TransactionProcessor transactionProcessor(KafkaConsumer<String, String> consumer,
                                                    @Value("${kafka.topic}") String topic,
                                                    TransactionTemplate transactionTemplate,
                                                    JdbcTemplate jdbcTemplate,
                                                    ObjectMapper objectMapper) {
        return new TransactionProcessor(consumer, topic, transactionTemplate, jdbcTemplate, objectMapper);
    }
}

class TransactionProcessor {
    private final KafkaConsumer<String, String> consumer;
    private final String topic;
    private final TransactionTemplate transactionTemplate;
    private final JdbcTemplate jdbcTemplate;
    private final ObjectMapper objectMapper;
    private final TransactionValidator validator;

    public TransactionProcessor(KafkaConsumer<String, String> consumer,
                              String topic,
                              TransactionTemplate transactionTemplate,
                              JdbcTemplate jdbcTemplate,
                              ObjectMapper objectMapper) {
        this.consumer = consumer;
        this.topic = topic;
        this.transactionTemplate = transactionTemplate;
        this.jdbcTemplate = jdbcTemplate;
        this.objectMapper = objectMapper;
        this.validator = new TransactionValidator();

        consumer.subscribe(Collections.singletonList(topic));

        startProcessing();
    }

    private void startProcessing() {
        Thread processingThread = new Thread(() -> {
            while (true) {
                var records = consumer.poll(Duration.ofMillis(100));
                for (ConsumerRecord<String, String> record : records) {
                    try {
                        String json = record.value();
                        Transaction transaction = objectMapper.readValue(json, Transaction.class);

                        if (validator.validate(transaction)) {
                            persistTransaction(transaction);
                        }
                    } catch (Exception e) {
                        System.err.println("Error processing record: " + e.getMessage());
                    }
                }
            }
        });
        processingThread.start();
    }

    private void persistTransaction(Transaction transaction) {
        transactionTemplate.execute(new TransactionCallback<Void>() {
            @Override
            public Void doInTransaction(TransactionStatus status) {
                try {
                    if (transaction instanceof Transaction.Purchase purchase) {
                        jdbcTemplate.update(
                            "INSERT INTO purchases (id, product_id, customer_id, amount, timestamp) VALUES (?, ?, ?, ?, ?)",
                            purchase.id(), purchase.productId(), purchase.customerId(), purchase.amount(), purchase.timestamp()
                        );
                    } else if (transaction instanceof Transaction.Refund refund) {
                        jdbcTemplate.update(
                            "INSERT INTO refunds (id, original_purchase_id, amount, reason, timestamp) VALUES (?, ?, ?, ?, ?)",
                            refund.id(), refund.originalPurchaseId(), refund.amount(), refund.reason(), refund.timestamp()
                        );
                    } else if (transaction instanceof Transaction.Subscription subscription) {
                        jdbcTemplate.update(
                            "INSERT INTO subscriptions (id, customer_id, plan_id, billing_period, amount, start_date) VALUES (?, ?, ?, ?, ?, ?)",
                            subscription.id(), subscription.customerId(), subscription.planId(), 
                            subscription.billingPeriod(), subscription.amount(), subscription.startDate()
                        );
                    }
                    return null;
                } catch (Exception e) {
                    status.setRollbackOnly();
                    System.err.println("Transaction failed, rolling back: " + e.getMessage());
                    throw e;
                }
            }
        });
    }
}

class TransactionValidator {
    public boolean validate(Transaction transaction) {
        return switch (transaction) {
            case Transaction.Purchase p -> validatePurchase(p);
            case Transaction.Refund r -> validateRefund(r);
            case Transaction.Subscription s -> validateSubscription(s);
            default -> false;
        };
    }

    private boolean validatePurchase(Transaction.Purchase purchase) {
        return purchase.id() != null && purchase.amount() > 0;
    }

    private boolean validateRefund(Transaction.Refund refund) {
        return refund.id() != null && refund.originalPurchaseId() != null && refund.amount() > 0;
    }

    private boolean validateSubscription(Transaction.Subscription subscription) {
        return subscription.id() != null && subscription.customerId() != null && 
               subscription.planId() != null && subscription.amount() > 0;
    }
}

sealed interface Transaction permits Transaction.Purchase, Transaction.Refund, Transaction.Subscription {
    String id();
    double amount();

    record Purchase(
        String id,
        String productId,
        String customerId,
        double amount,
        long timestamp
    ) implements Transaction {}

    record Refund(
        String id,
        String originalPurchaseId,
        double amount,
        String reason,
        long timestamp
    ) implements Transaction {}

    record Subscription(
        String id,
        String customerId,
        String planId,
        String billingPeriod,
        double amount,
        long startDate
    ) implements Transaction {}
}
