I'll create a Rust command line tool that monitors a directory and uploads new files to an AWS S3 bucket. Here's the implementation:

```rust:src/main.rs
use aws_sdk_s3::Client as S3Client;
use aws_sdk_s3::config::Region;
use aws_config::BehaviorVersion;
use clap::Parser;
use env_logger::Builder;
use log::{error, info, LevelFilter};
use notify::{Config, Event, EventKind, RecommendedWatcher, RecursiveMode, Watcher};
use std::path::{Path, PathBuf};
use std::sync::Arc;
use tokio::sync::mpsc::{self, Sender};

#[derive(Parser, Debug)]
#[command(author, version, about, long_about = None)]
struct Args {
    /// Directory to monitor for new files
    #[arg(short, long)]
    directory: PathBuf,

    /// AWS S3 bucket name
    #[arg(short, long)]
    bucket: String,

    /// AWS region
    #[arg(short, long, default_value = "us-east-1")]
    region: String,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Initialize logger
    Builder::new()
        .filter_level(LevelFilter::Info)
        .init();

    // Parse command line args
    let args = Args::parse();

    // Initialize AWS SDK
    let config = aws_config::defaults(BehaviorVersion::latest())
        .region(Region::new(args.region))
        .load()
        .await;

    let s3_client = Arc::new(S3Client::new(&config));
    let bucket_name = Arc::new(args.bucket);

    // Create channel for events
    let (tx, mut rx) = mpsc::channel(100);

    // Start file watcher
    let mut watcher = start_watcher(tx, args.directory)?;

    // Process events
    info!("Monitoring directory for new files...");
    while let Some(event) = rx.recv().await {
        match event {
            Ok(event) => handle_event(event, Arc::clone(&s3_client), Arc::clone(&bucket_name)).await,
            Err(e) => error!("Error watching directory: {}", e),
        }
    }

    // Keep watcher alive until the end
    drop(watcher);

    Ok(())
}

fn start_watcher(tx: Sender<Result<Event, notify::Error>>, directory: PathBuf) -> Result<RecommendedWatcher, notify::Error> {
    let mut watcher = RecommendedWatcher::new(
        move |res| {
            let tx = tx.clone();
            tokio::spawn(async move {
                let _ = tx.send(res).await;
            });
        },
        Config::default(),
    )?;

    watcher.watch(&directory, RecursiveMode::Recursive)?;
    info!("Started watching directory: {:?}", directory);

    Ok(watcher)
}

async fn handle_event(event: Event, s3_client: Arc<S3Client>, bucket_name: Arc<String>) {
    if let EventKind::Create(_) = event.kind {
        for path in event.paths {
            if path.is_file() {
                let s3_client = Arc::clone(&s3_client);
                let bucket_name = Arc::clone(&bucket_name);
                let path_clone = path.clone();

                tokio::task::spawn(async move {
                    match upload_file(&path_clone, &s3_client, &bucket_name).await {
                        Ok(_) => info!("Successfully uploaded {:?}", path_clone),
                        Err(e) => error!("Failed to upload {:?}: {}", path_clone, e),
                    }
                });
            }
        }
    }
}

async fn upload_file(path: &Path, s3_client: &S3Client, bucket_name: &str) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
    let file_name = path.file_name()
        .ok_or("Invalid file name")?
        .to_str()
        .ok_or("File name is not valid UTF-8")?;

    let file_path = path.to_path_buf();

    // Use spawn_blocking for file I/O operations
    let file_content = tokio::task::spawn_blocking(move || -> Result<Vec<u8>, std::io::Error> {
        std::fs::read(file_path)
    }).await??;

    s3_client.put_object()
        .bucket(bucket_name)
        .key(file_name)
        .body(file_content.into())
        .send()
        .await?;

    Ok(())
}
