package com.stockanalyzer.service;

import com.stockanalyzer.model.StockData;
import java.time.Instant;
import java.util.List;
import java.util.Random;
import java.util.concurrent.Flow.Publisher;
import java.util.concurrent.Flow.Subscriber;
import java.util.concurrent.SubmissionPublisher;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

public class StockStreamSimulator implements Publisher<StockData> {
    private final SubmissionPublisher<StockData> publisher;
    private final List<String> stockSymbols = List.of("AAPL", "MSFT", "GOOGL", "AMZN", "TSLA");
    private final Random random = new Random();
    private final ScheduledExecutorService scheduler = Executors.newSingleThreadScheduledExecutor();

    public StockStreamSimulator() {
        this.publisher = new SubmissionPublisher<>(Executors.newVirtualThreadPerTaskExecutor(), 256);
        startSimulation();
    }

    private void startSimulation() {
        scheduler.scheduleAtFixedRate(() -> {
            for (String symbol : stockSymbols) {
                double basePrice = switch(symbol) {
                    case "AAPL" -> 180.0;
                    case "MSFT" -> 330.0;
                    case "GOOGL" -> 140.0;
                    case "AMZN" -> 130.0;
                    case "TSLA" -> 240.0;
                    default -> 100.0;
                };

                double fluctuation = (random.nextDouble() - 0.5) * 2.0; // -1.0 to 1.0
                double price = basePrice + basePrice * (fluctuation / 100.0);
                long volume = random.nextInt(10000) + 1000;

                StockData data = new StockData(symbol, price, volume, Instant.now());
                publisher.submit(data);
            }
        }, 0, 1, TimeUnit.SECONDS);
    }

    @Override
    public void subscribe(Subscriber<? super StockData> subscriber) {
        publisher.subscribe(subscriber);
    }

    public void close() {
        scheduler.shutdown();
        publisher.close();
    }
}
