```java:src/main/java/com/stockanalyzer/service/StockAnalyzer.java
package com.stockanalyzer.service;

import com.stockanalyzer.model.StockData;
import com.stockanalyzer.model.StockMetrics;

import java.util.Map;
import java.util.Queue;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentLinkedQueue;
import java.util.concurrent.Flow.Subscriber;
import java.util.concurrent.Flow.Subscription;
import java.util.concurrent.atomic.AtomicReference;

public class StockAnalyzer implements Subscriber<StockData> {
    private final Map<String, Queue<StockData>> stockDataMap = new ConcurrentHashMap<>();
    private final Map<String, AtomicReference<StockMetrics>> metricsMap = new ConcurrentHashMap<>();
    private final int windowSize;
    private Subscription subscription;

    public StockAnalyzer(int windowSize) {
        this.windowSize = windowSize;
    }

    @Override
    public void onSubscribe(Subscription subscription) {
        this.subscription = subscription;
        subscription.request(Long.MAX_VALUE);
    }

    @Override
    public void onNext(StockData data) {
        stockDataMap.computeIfAbsent(data.symbol(), k -> new ConcurrentLinkedQueue<>()).add(data);

        Queue<StockData> dataQueue = stockDataMap.get(data.symbol());
        while (dataQueue.size() > windowSize) {
            dataQueue.poll();
        }

        calculateMetrics(data.symbol());
    }

    private void calculateMetrics(String symbol) {
        Queue<StockData> dataQueue = stockDataMap.get(symbol);
        if (dataQueue.size() < 2) return;

        double sum = 0;
        double highest = Double.MIN_VALUE;
        double lowest = Double.MAX_VALUE;
        double[] prices = new double[dataQueue.size()];

        int i = 0;
        for (StockData data : dataQueue) {
            double price = data.price();
            sum += price;
            highest = Math.max(highest, price);
            lowest = Math.min(lowest, price);
            prices[i++] = price;
        }

        double avg = sum / dataQueue.size();

        // Calculate volatility (standard deviation)
        double variance = 0;
        for (double price : prices) {
            variance += Math.pow(price - avg, 2);
        }
        double volatility = Math.sqrt(variance / prices.length);

        // Alert if volatility exceeds 2%
        boolean alert = volatility / avg > 0.02;

        StockMetrics metrics = new StockMetrics(symbol, avg, volatility, highest, lowest, alert);
        metricsMap.computeIfAbsent(symbol, k -> new AtomicReference<>()).set(metrics);
    }

    public StockMetrics getMetrics(String symbol) {
        AtomicReference<StockMetrics> ref = metricsMap.get(symbol);
        return ref != null ? ref.get() : null;
    }

    public Map<String, AtomicReference<StockMetrics>> getAllMetrics() {
        return metricsMap;
    }

    @Override
    public void onError(Throwable throwable) {
        throwable.printStackTrace();
    }

    @Override
    public void onComplete() {
        System.out.println("Stock stream completed");
    }
}
