package com.stockanalyzer.api;

import com.stockanalyzer.model.StockMetrics;
import com.stockanalyzer.service.StockAnalyzer;
import io.javalin.Javalin;
import io.javalin.http.Context;

import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.atomic.AtomicReference;

public class StockAnalysisController {
    private final StockAnalyzer analyzer;
    private final Javalin app;

    public StockAnalysisController(StockAnalyzer analyzer, int port) {
        this.analyzer = analyzer;
        this.app = Javalin.create()
            .get("/api/stocks", this::getAllStocks)
            .get("/api/stocks/{symbol}", this::getStockBySymbol)
            .get("/api/alerts", this::getAlerts);

        app.start(port);
    }

    private void getAllStocks(Context ctx) {
        Map<String, StockMetrics> result = new HashMap<>();
        analyzer.getAllMetrics().forEach((symbol, ref) -> {
            StockMetrics metrics = ref.get();
            if (metrics != null) {
                result.put(symbol, metrics);
            }
        });
        ctx.json(result);
    }

    private void getStockBySymbol(Context ctx) {
        String symbol = ctx.pathParam("symbol");
        StockMetrics metrics = analyzer.getMetrics(symbol);

        if (metrics != null) {
            ctx.json(metrics);
        } else {
            ctx.status(404).result("Stock not found");
        }
    }

    private void getAlerts(Context ctx) {
        Map<String, StockMetrics> alerts = new HashMap<>();
        analyzer.getAllMetrics().forEach((symbol, ref) -> {
            StockMetrics metrics = ref.get();
            if (metrics != null && metrics.alertTriggered()) {
                alerts.put(symbol, metrics);
            }
        });
        ctx.json(alerts);
    }

    public void stop() {
        app.stop();
    }
}
