Here's a Rust-based command-line application for efficient image migration with resizing functionality:

```rust
use clap::{App, Arg};
use image::{ImageFormat, GenericImageView};
use indicatif::{ProgressBar, ProgressStyle};
use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex};
use std::fs;
use tokio::runtime::Runtime;
use tokio::task;
use tokio::sync::Semaphore;
use std::error::Error;
use std::io;

#[derive(Debug, Clone)]
struct Config {
    source_dir: PathBuf,
    target_dir: PathBuf,
    width: u32,
    height: u32,
    maintain_aspect_ratio: bool,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    let matches = App::new("Image Migration Tool")
        .version("1.0")
        .author("Developer")
        .about("Migrates and resizes images between directories")
        .arg(Arg::with_name("source")
            .short("s")
            .long("source")
            .value_name("SOURCE_DIR")
            .help("Source directory containing images")
            .required(true))
        .arg(Arg::with_name("target")
            .short("t")
            .long("target")
            .value_name("TARGET_DIR")
            .help("Target directory for processed images")
            .required(true))
        .arg(Arg::with_name("width")
            .short("w")
            .long("width")
            .value_name("WIDTH")
            .help("Target width for resized images")
            .default_value("800"))
        .arg(Arg::with_name("height")
            .short("h")
            .long("height")
            .value_name("HEIGHT")
            .help("Target height for resized images")
            .default_value("600"))
        .arg(Arg::with_name("keep-aspect")
            .long("keep-aspect")
            .help("Maintain aspect ratio when resizing")
            .takes_value(false))
        .get_matches();

    let config = Config {
        source_dir: PathBuf::from(matches.value_of("source").unwrap()),
        target_dir: PathBuf::from(matches.value_of("target").unwrap()),
        width: matches.value_of("width").unwrap().parse().unwrap_or(800),
        height: matches.value_of("height").unwrap().parse().unwrap_or(600),
        maintain_aspect_ratio: matches.is_present("keep-aspect"),
    };

    // Ensure target directory exists
    fs::create_dir_all(&config.target_dir)?;

    // Find all JPG and PNG files
    let files = find_image_files(&config.source_dir)?;
    let total_files = files.len();

    if total_files == 0 {
        println!("No image files found in the source directory.");
        return Ok(());
    }

    println!("Found {} image files to process", total_files);

    // Create progress bar
    let progress_bar = Arc::new(Mutex::new(ProgressBar::new(total_files as u64)));
    progress_bar.lock().unwrap().set_style(
        ProgressStyle::default_bar()
            .template("{spinner:.green} [{elapsed_precise}] [{bar:40.cyan/blue}] {pos}/{len} ({eta})")
            .unwrap()
            .progress_chars("#>-")
    );

    // Create semaphore to limit concurrent tasks
    let semaphore = Arc::new(Semaphore::new(10)); // 10 concurrent workers
    let config = Arc::new(config);
    let mut handles = vec![];

    for file in files {
        let sem_permit = semaphore.clone().acquire_owned().await?;
        let config = config.clone();
        let progress_bar = progress_bar.clone();

        let handle = tokio::spawn(async move {
            let result = process_image(&file, &config).await;
            progress_bar.lock().unwrap().inc(1);
            drop(sem_permit); // Release the permit
            result
        });

        handles.push(handle);
    }

    // Wait for all tasks to complete
    let results: Vec<Result<(), Box<dyn Error + Send + Sync>>> = futures::future::join_all(handles)
        .await
        .into_iter()
        .map(|r| r.unwrap())
        .collect();

    let successful = results.iter().filter(|r| r.is_ok()).count();
    let failed = total_files - successful;

    progress_bar.lock().unwrap().finish_with_message("Processing complete");
    println!("Migration complete: {} files processed successfully, {} failed", successful, failed);

    Ok(())
}

async fn process_image(
    source_path: &Path,
    config: &Config
) -> Result<(), Box<dyn Error + Send + Sync>> {
    // Process in a separate blocking thread since image operations are CPU-bound
    let source_path = source_path.to_path_buf();
    let config = config.clone();

    task::spawn_blocking(move || -> Result<(), Box<dyn Error + Send + Sync>> {
        let file_name = source_path.file_name().ok_or("Invalid file name")?;
        let target_path = config.target_dir.join(file_name);

        // Open the image
        let img = image::open(&source_path)?;

        // Resize the image
        let resized = if config.maintain_aspect_ratio {
            let (width, height) = img.dimensions();
            let ratio = width as f32 / height as f32;

            let (new_width, new_height) = if ratio > 1.0 {
                // Width is larger
                let new_width = config.width;
                let new_height = (config.width as f32 / ratio) as u32;
                (new_width, new_height)
            } else {
                // Height is larger or equal
                let new_height = config.height;
                let new_width = (config.height as f32 * ratio) as u32;
                (new_width, new_height)
            };

            img.resize(new_width, new_height, image::imageops::FilterType::Lanczos3)
        } else {
            img.resize_exact(config.width, config.height, image::imageops::FilterType::Lanczos3)
        };

        // Save the resized image
        resized.save(&target_path)?;

        // Remove original file if save was successful
        fs::remove_file(&source_path)?;

        Ok(())
    }).await?
}

fn find_image_files(dir: &Path) -> io::Result<Vec<PathBuf>> {
    let mut image_files = Vec::new();

    if dir.is_dir() {
        for entry in fs::read_dir(dir)? {
            let entry = entry?;
            let path = entry.path();

            if path.is_dir() {
                let mut sub_dir_files = find_image_files(&path)?;
                image_files.append(&mut sub_dir_files);
            } else if let Some(extension) = path.extension() {
                let ext = extension.to_string_lossy().to_lowercase();
                if ext == "jpg" || ext == "jpeg" || ext == "png" {
                    image_files.push(path);
                }
            }
        }
    }

    Ok(image_files)
}
