Here's a Rust utility that concurrently compresses files using GZIP:

```rust
use std::io::{self, BufRead, BufReader, Write};
use std::fs::{self, File};
use std::path::{Path, PathBuf};
use std::sync::mpsc;
use std::thread;
use flate2::write::GzEncoder;
use flate2::Compression;

fn main() -> io::Result<()> {
    // Number of worker threads to use
    let num_threads = num_cpus::get();

    // Channel for sending filenames to worker threads
    let (tx, rx) = mpsc::channel();

    // Share the receiver between multiple worker threads
    let rx = std::sync::Arc::new(std::sync::Mutex::new(rx));

    // Spawn worker threads
    let mut handles = Vec::with_capacity(num_threads);
    for _ in 0..num_threads {
        let thread_rx = rx.clone();
        let handle = thread::spawn(move || {
            loop {
                // Try to get a filename from the channel
                let filename = match thread_rx.lock().unwrap().recv() {
                    Ok(name) => name,
                    Err(_) => break, // Channel closed, exit the loop
                };

                if let Err(e) = compress_file(&filename) {
                    eprintln!("Error compressing {}: {}", filename, e);
                }
            }
        });
        handles.push(handle);
    }

    // Read filenames from stdin and send them to worker threads
    let stdin = io::stdin();
    let reader = BufReader::new(stdin.lock());

    for line in reader.lines() {
        let filename = line?;
        tx.send(filename).expect("Failed to send filename to worker");
    }

    // Drop the sender to signal that no more filenames will be sent
    drop(tx);

    // Wait for all worker threads to finish
    for handle in handles {
        handle.join().expect("Worker thread panicked");
    }

    Ok(())
}

fn compress_file(filename: &str) -> io::Result<()> {
    let path = Path::new(filename);

    // Create output path with .gz extension
    let mut output_path = PathBuf::from(path);
    let file_stem = path.file_name().ok_or_else(|| {
        io::Error::new(io::ErrorKind::InvalidInput, "Invalid filename")
    })?;
    let mut output_filename = file_stem.to_os_string();
    output_filename.push(".gz");
    output_path.set_file_name(output_filename);

    // Create a pipe for reading from the file and writing to the compressor
    let (mut reader, mut writer) = pipe::pipe();

    // Spawn a thread to read the file and write to the pipe
    let filename_clone = filename.to_string();
    let read_handle = thread::spawn(move || -> io::Result<()> {
        let mut file = File::open(&filename_clone)?;
        io::copy(&mut file, &mut writer)?;
        Ok(())
    });

    // Create the output file with a GzEncoder
    let output_file = File::create(output_path)?;
    let mut encoder = GzEncoder::new(output_file, Compression::default());

    // Read from the pipe and write to the encoder
    io::copy(&mut reader, &mut encoder)?;

    // Finish the compression
    encoder.finish()?;

    // Wait for the read thread to finish
    read_handle.join().expect("Read thread panicked").map_err(|e| {
        io::Error::new(io::ErrorKind::Other, format!("Read error: {}", e))
    })?;

    Ok(())
}
