package com.document.preview;

import org.apache.pdfbox.pdmodel.PDDocument;
import org.apache.pdfbox.text.PDFTextStripper;
import org.apache.poi.xwpf.extractor.XWPFWordExtractor;
import org.apache.poi.xwpf.usermodel.XWPFDocument;

import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Arrays;
import java.util.HashMap;
import java.util.Map;
import java.util.stream.Collectors;

public class DocumentPreviewService {

    public DocumentSummary generateSummary(File file) throws IOException {
        String extension = getFileExtension(file.getName());
        String content = extractContent(file, extension);

        DocumentSummary summary = new DocumentSummary();
        summary.setFileName(file.getName());
        summary.setFileType(extension.toUpperCase());
        summary.setWordCount(countWords(content));
        summary.setCharacterCount(content.length());
        summary.setDetectedLanguage(detectLanguage(content));
        summary.setSummary(generateTextSummary(content));

        return summary;
    }

    private String extractContent(File file, String extension) throws IOException {
        switch (extension.toLowerCase()) {
            case "pdf":
                return extractPdfContent(file);
            case "docx":
                return extractDocxContent(file);
            case "txt":
                return extractTxtContent(file);
            default:
                throw new UnsupportedOperationException("Unsupported file type: " + extension);
        }
    }

    private String extractPdfContent(File file) throws IOException {
        try (PDDocument document = PDDocument.load(file)) {
            PDFTextStripper stripper = new PDFTextStripper();
            return stripper.getText(document);
        }
    }

    private String extractDocxContent(File file) throws IOException {
        try (XWPFDocument document = new XWPFDocument(Files.newInputStream(file.toPath()))) {
            XWPFWordExtractor extractor = new XWPFWordExtractor(document);
            return extractor.getText();
        }
    }

    private String extractTxtContent(File file) throws IOException {
        return Files.readString(file.toPath(), StandardCharsets.UTF_8);
    }

    private int countWords(String content) {
        if (content == null || content.isEmpty()) {
            return 0;
        }
        return content.split("\\s+").length;
    }

    private String detectLanguage(String content) {
        // Simple language detection based on character frequency
        // This is a basic implementation and should be replaced with a proper language detection library
        if (content == null || content.length() < 10) {
            return "Unknown";
        }

        Map<String, String> languagePatterns = new HashMap<>();
        languagePatterns.put("en", "the and that have with");
        languagePatterns.put("es", "el la que los del");
        languagePatterns.put("fr", "le la les des que");
        languagePatterns.put("de", "der die das und zu");

        String contentLower = content.toLowerCase();
        String detectedLanguage = "Unknown";
        int highestMatches = 0;

        for (Map.Entry<String, String> entry : languagePatterns.entrySet()) {
            String[] patterns = entry.getValue().split(" ");
            int matches = 0;

            for (String pattern : patterns) {
                if (contentLower.contains(pattern)) {
                    matches++;
                }
            }

            if (matches > highestMatches) {
                highestMatches = matches;
                detectedLanguage = entry.getKey();
            }
        }

        return detectedLanguage;
    }

    private String generateTextSummary(String content) {
        // Simple summary generation - first 200 characters or less
        if (content == null) {
            return "";
        }

        int summaryLength = Math.min(content.length(), 200);
        String summary = content.substring(0, summaryLength);

        if (summaryLength < content.length()) {
            summary += "...";
        }

        return summary;
    }

    private String getFileExtension(String fileName) {
        int dotIndex = fileName.lastIndexOf('.');
        if (dotIndex > 0 && dotIndex < fileName.length() - 1) {
            return fileName.substring(dotIndex + 1);
        }
        return "";
    }
}
