package com.document.preview;

import com.sun.net.httpserver.HttpExchange;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpServer;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;
import java.net.InetSocketAddress;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.StandardCopyOption;
import java.util.HashMap;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.Executors;

public class DocumentPreviewController {
    private final int port;
    private final HttpServer server;
    private final DocumentPreviewService previewService;
    private final ObjectMapper objectMapper;
    private final Path tempDir;

    public DocumentPreviewController(int port) throws IOException {
        this.port = port;
        this.server = HttpServer.create(new InetSocketAddress(port), 0);
        this.previewService = new DocumentPreviewService();
        this.objectMapper = new ObjectMapper();
        this.tempDir = Files.createTempDirectory("document-preview-");

        server.createContext("/api/preview", new PreviewHandler());
        server.setExecutor(Executors.newFixedThreadPool(10));
    }

    public void start() {
        server.start();
        System.out.println("Document Preview Service started on port " + port);
    }

    public void stop() {
        server.stop(0);
        System.out.println("Document Preview Service stopped");
    }

    private class PreviewHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            try {
                if ("POST".equals(exchange.getRequestMethod())) {
                    handleFileUpload(exchange);
                } else {
                    sendResponse(exchange, 405, "Method Not Allowed");
                }
            } catch (Exception e) {
                e.printStackTrace();
                Map<String, String> errorResponse = new HashMap<>();
                errorResponse.put("error", e.getMessage());
                sendJsonResponse(exchange, 500, errorResponse);
            }
        }

        private void handleFileUpload(HttpExchange exchange) throws IOException {
            // Extract content type and boundary from headers
            String contentType = exchange.getRequestHeaders().getFirst("Content-Type");
            if (contentType == null || !contentType.startsWith("multipart/form-data")) {
                sendResponse(exchange, 400, "Expected multipart/form-data");
                return;
            }

            // Save uploaded file to temp directory
            File tempFile = Files.createTempFile(tempDir, "upload-", "").toFile();
            try (InputStream is = exchange.getRequestBody()) {
                Files.copy(is, tempFile.toPath(), StandardCopyOption.REPLACE_EXISTING);
            }

            // Generate document summary
            DocumentSummary summary = previewService.generateSummary(tempFile);

            // Clean up temp file
            tempFile.delete();

            // Send JSON response
            sendJsonResponse(exchange, 200, summary);
        }

        private void sendJsonResponse(HttpExchange exchange, int statusCode, Object response) throws IOException {
            String jsonResponse = objectMapper.writeValueAsString(response);
            exchange.getResponseHeaders().set("Content-Type", "application/json");
            sendResponse(exchange, statusCode, jsonResponse);
        }

        private void sendResponse(HttpExchange exchange, int statusCode, String response) throws IOException {
            byte[] responseBytes = response.getBytes(StandardCharsets.UTF_8);
            exchange.sendResponseHeaders(statusCode, responseBytes.length);
            try (OutputStream os = exchange.getResponseBody()) {
                os.write(responseBytes);
            }
        }
    }

    public static void main(String[] args) {
        try {
            int port = 8080;
            DocumentPreviewController controller = new DocumentPreviewController(port);
            controller.start();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}
