package com.document.preview;

import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.file.Path;
import java.time.Duration;

public class DocumentPreviewClient {
    private final HttpClient httpClient;
    private final String baseUrl;

    public DocumentPreviewClient(String baseUrl) {
        this.baseUrl = baseUrl;
        this.httpClient = HttpClient.newBuilder()
                .version(HttpClient.Version.HTTP_1_1)
                .connectTimeout(Duration.ofSeconds(10))
                .build();
    }

    public String previewDocument(Path filePath) throws IOException, InterruptedException {
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(baseUrl + "/api/preview"))
                .header("Content-Type", "multipart/form-data; boundary=boundary")
                .POST(buildMultipartBody(filePath))
                .build();

        HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

        if (response.statusCode() != 200) {
            throw new IOException("Error previewing document: " + response.body());
        }

        return response.body();
    }

    private HttpRequest.BodyPublisher buildMultipartBody(Path filePath) throws IOException {
        String boundary = "boundary";
        String fileName = filePath.getFileName().toString();

        String content = "--" + boundary + "\r\n" +
                "Content-Disposition: form-data; name=\"file\"; filename=\"" + fileName + "\"\r\n" +
                "Content-Type: application/octet-stream\r\n\r\n";

        byte[] fileContent = java.nio.file.Files.readAllBytes(filePath);

        String end = "\r\n--" + boundary + "--\r\n";

        return HttpRequest.BodyPublishers.ofByteArrays(
                java.util.Arrays.asList(
                        content.getBytes(),
                        fileContent,
                        end.getBytes()
                )
        );
    }

    public static void main(String[] args) {
        if (args.length != 1) {
            System.out.println("Usage: DocumentPreviewClient <file-path>");
            return;
        }

        try {
            DocumentPreviewClient client = new DocumentPreviewClient("http://localhost:8080");
            String result = client.previewDocument(Path.of(args[0]));
            System.out.println("Document preview result:");
            System.out.println(result);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
